#!/usr/bin/env python3
# GranoVital IA - Sprint Final (verificacion QA)
# Resuelve: BUG-005(confirmado), BUG-009, 010, 011, 015, 017, 019, 020, 026
# USO: python sprint_final_fix.py C:\GranoVital-IA

import os, sys, shutil
from pathlib import Path
from datetime import datetime

BASE = Path(sys.argv[1]) if len(sys.argv) > 1 else Path(r"C:\GranoVital-IA")
print("\nGranoVital IA - Sprint Final Fix")
print(f"   Ruta base: {BASE}")

if not (BASE / "Backend").exists():
    print(f"ERROR: No se encontro Backend/ en {BASE}")
    sys.exit(1)

backup_dir = BASE / f"_backup_sprint_final_{datetime.now().strftime('%Y%m%d_%H%M%S')}"
print(f"Backup en: {backup_dir.name}/\n")

ARCHIVOS = {}

ARCHIVOS["frontend/src/pages/InteligenciaArtificial.jsx"] = '// ==============================================================\n// modulo_04_ia / frontend/src/pages/InteligenciaArtificial.jsx\n// Dashboard principal del Modulo de IA\n//\n// RF-05  Carga y analisis de imagen para enfermedades\n// RF-06  Carga y analisis de imagen para plagas\n// RF-07  Prediccion fitosanitaria con un clic\n// RF-08  Recomendacion de riego con un clic\n// RF-09  Recomendacion de fertilizacion con un clic\n// RN-03  Banner de validez de datos visible siempre\n// RNF-02 Interfaz para usuarios sin perfil tecnico\n// RNF-07 Responsive web y movil\n// ==============================================================\n\nimport { useState, useEffect, useRef } from "react";\nimport { iaService } from "../services/iaService";\n\n// ── Colores GranoVital ──────────────────────────────────────\nconst C = {\n  cafe:    "#6f3a1b", cafeCla: "#a0522d", verde:  "#2d7a3a",\n  amarillo:"#c8a000", rojo:    "#b91c1c", azul:   "#0284c7",\n  gris:    "#f5f0eb", borde:   "#d4b896", texto:  "#1a0e05",\n};\n\n// ── Paleta de urgencia ──────────────────────────────────────\nconst URGENCIA_COLOR = {\n  bajo:     { bg: "#f0fdf4", borde: C.verde,    texto: C.verde    },\n  medio:    { bg: "#fffbeb", borde: C.amarillo, texto: C.amarillo },\n  alto:     { bg: "#fff7ed", borde: "#ea580c",  texto: "#ea580c"  },\n  critico:  { bg: "#fff1f0", borde: C.rojo,     texto: C.rojo     },\n  moderado: { bg: "#fffbeb", borde: C.amarillo, texto: C.amarillo },\n};\nconst RIESGO_ICONO = { bajo:"🟢", moderado:"🟡", alto:"🟠", critico:"🔴" };\n\n// ── Subcomponentes ───────────────────────────────────────────\n\nfunction Modal({ abierto, titulo, onCerrar, children }) {\n  if (!abierto) return null;\n  return (\n    <div style={{\n      position:"fixed", inset:0, background:"rgba(0,0,0,0.45)",\n      display:"flex", alignItems:"center", justifyContent:"center",\n      zIndex:1000, padding:"1rem",\n    }}>\n      <div style={{\n        background:"#fff", borderRadius:"16px", padding:"2rem",\n        width:"100%", maxWidth:"580px", maxHeight:"90vh",\n        overflowY:"auto", boxShadow:"0 20px 60px rgba(0,0,0,0.3)",\n      }}>\n        <div style={{ display:"flex", justifyContent:"space-between", marginBottom:"1.5rem" }}>\n          <h3 style={{ margin:0, color:C.cafe }}>{titulo}</h3>\n          <button onClick={onCerrar}\n            style={{ background:"none", border:"none", fontSize:"1.4rem", cursor:"pointer" }}>✕</button>\n        </div>\n        {children}\n      </div>\n    </div>\n  );\n}\n\nfunction Badge({ texto, urgencia = "bajo" }) {\n  const col = URGENCIA_COLOR[urgencia] || URGENCIA_COLOR.bajo;\n  return (\n    <span style={{\n      background:col.bg, border:`1.5px solid ${col.borde}`,\n      color:col.texto, borderRadius:"999px",\n      padding:"0.2rem 0.8rem", fontSize:"0.78rem", fontWeight:700,\n    }}>\n      {texto}\n    </span>\n  );\n}\n\nfunction BannerRN03({ validez }) {\n  if (!validez) return null;\n  const ok = validez.datos_validos_rn03;\n  return (\n    <div style={{\n      background: ok ? "#f0fdf4" : "#fffbeb",\n      border:`1.5px solid ${ok ? C.verde : C.amarillo}`,\n      borderRadius:"12px", padding:"1rem 1.4rem",\n      display:"flex", alignItems:"center", gap:"0.8rem",\n    }}>\n      <span style={{ fontSize:"1.5rem" }}>{ok ? "✅" : "⚠️"}</span>\n      <div>\n        <p style={{ margin:0, fontWeight:700, color: ok ? C.verde : C.amarillo }}>\n          {ok ? "Datos actualizados — IA completamente disponible"\n               : "Datos desactualizados — IA limitada (RN-03)"}\n        </p>\n        <p style={{ margin:"0.2rem 0 0", fontSize:"0.83rem", color:"#7a5c3a" }}>\n          {validez.mensaje_rn03}\n        </p>\n      </div>\n    </div>\n  );\n}\n\nfunction TarjetaResultado({ titulo, icono, datos, cargando, error, onAccion, textoAccion, urgencia }) {\n  const col = URGENCIA_COLOR[urgencia] || { bg:"#fff", borde:C.borde };\n  return (\n    <div style={{\n      background:col.bg, border:`1.5px solid ${col.borde}`,\n      borderRadius:"14px", padding:"1.2rem 1.4rem",\n    }}>\n      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:"0.8rem" }}>\n        <h3 style={{ margin:0, fontSize:"1rem", color:C.cafe }}>\n          {icono} {titulo}\n        </h3>\n        {onAccion && (\n          <button onClick={onAccion} disabled={cargando}\n            style={{\n              padding:"0.45rem 1rem", borderRadius:"8px", border:"none",\n              background: cargando ? "#c9a88a" : C.cafe,\n              color:"#fff", fontWeight:700, cursor: cargando ? "not-allowed" : "pointer",\n              fontSize:"0.82rem",\n            }}>\n            {cargando ? "Analizando..." : textoAccion || "Ejecutar"}\n          </button>\n        )}\n      </div>\n\n      {error && (\n        <div style={{\n          background:"#fff1f0", border:"1px solid #ffccc7",\n          borderRadius:"8px", padding:"0.6rem", color:C.rojo,\n          fontSize:"0.83rem", marginBottom:"0.6rem",\n        }}>\n          {error}\n        </div>\n      )}\n\n      {datos && (\n        <div style={{ fontSize:"0.88rem", lineHeight:1.6 }}>\n          {datos}\n        </div>\n      )}\n\n      {!datos && !cargando && !error && (\n        <p style={{ color:"#bbb", fontSize:"0.85rem", margin:0 }}>\n          Sin resultados aun. Ejecute el analisis.\n        </p>\n      )}\n    </div>\n  );\n}\n\n// ── Panel de imagen para RF-05 / RF-06 ───────────────────────\n\nfunction PanelImagen({ tipo, cultivoId, onResultado }) {\n  const [archivo,   setArchivo]   = useState(null);\n  const [preview,   setPreview]   = useState(null);\n  const [cargando,  setCargando]  = useState(false);\n  const [error,     setError]     = useState("");\n  const [resultado, setResultado] = useState(null);\n  const inputRef = useRef();\n\n  const seleccionar = (e) => {\n    const f = e.target.files[0];\n    if (!f) return;\n    setArchivo(f);\n    setPreview(URL.createObjectURL(f));\n    setResultado(null);\n    setError("");\n  };\n\n  const analizar = async () => {\n    if (!archivo) return;\n    setCargando(true);\n    setError("");\n    try {\n      const fn   = tipo === "enfermedad"\n        ? iaService.analizarEnfermedad\n        : iaService.analizarPlaga;\n      const res  = await fn(cultivoId, archivo);\n      setResultado(res);\n      onResultado && onResultado(res);\n    } catch (e) {\n      setError(e.message);\n    } finally {\n      setCargando(false);\n    }\n  };\n\n  const col = resultado ? (URGENCIA_COLOR[resultado.nivel_urgencia] || URGENCIA_COLOR.bajo) : null;\n\n  return (\n    <div style={{ display:"flex", flexDirection:"column", gap:"1rem" }}>\n      {/* Zona de carga */}\n      <div\n        onClick={() => inputRef.current.click()}\n        style={{\n          border:`2px dashed ${C.borde}`, borderRadius:"12px",\n          padding:"2rem", textAlign:"center", cursor:"pointer",\n          background: preview ? "#000" : C.gris,\n          position:"relative", overflow:"hidden", minHeight:"180px",\n          display:"flex", alignItems:"center", justifyContent:"center",\n        }}\n      >\n        {preview\n          ? <img src={preview} alt="preview"\n              style={{ maxWidth:"100%", maxHeight:"250px", borderRadius:"8px" }} />\n          : <div>\n              <p style={{ fontSize:"2.5rem", margin:"0 0 0.5rem" }}>📷</p>\n              <p style={{ margin:0, color:C.cafeCla, fontWeight:600 }}>\n                Haga clic para seleccionar imagen\n              </p>\n              <p style={{ margin:0, fontSize:"0.78rem", color:"#9a7a5a" }}>\n                JPG, PNG o WEBP — max 10 MB\n              </p>\n            </div>\n        }\n        <input ref={inputRef} type="file" accept="image/*"\n          onChange={seleccionar} style={{ display:"none" }} />\n      </div>\n\n      {archivo && (\n        <button onClick={analizar} disabled={cargando}\n          style={{\n            padding:"0.75rem", borderRadius:"10px", border:"none",\n            background: cargando ? "#c9a88a"\n              : "linear-gradient(135deg, #6f3a1b, #a0522d)",\n            color:"#fff", fontWeight:800, fontSize:"1rem",\n            cursor: cargando ? "not-allowed" : "pointer",\n          }}>\n          {cargando ? "⏳ Analizando imagen..." : "🔬 Analizar imagen"}\n        </button>\n      )}\n\n      {error && (\n        <div style={{\n          background:"#fff1f0", border:"1px solid #ffccc7",\n          borderRadius:"8px", padding:"0.8rem", color:C.rojo,\n        }}>{error}</div>\n      )}\n\n      {resultado && col && (\n        <div style={{\n          background:col.bg, border:`2px solid ${col.borde}`,\n          borderRadius:"12px", padding:"1.2rem",\n        }}>\n          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>\n            <h4 style={{ margin:0, color:col.texto }}>{resultado.diagnostico}</h4>\n            <Badge texto={resultado.nivel_urgencia.toUpperCase()} urgencia={resultado.nivel_urgencia} />\n          </div>\n          <p style={{ margin:"0.4rem 0", fontSize:"0.85rem", color:"#7a5c3a" }}>\n            Confianza: <strong>{resultado.confianza_pct}</strong>\n            {" · "}{resultado.tiempo_pct_rnf01}\n          </p>\n\n          {/* Top clases */}\n          <div style={{ margin:"0.8rem 0", display:"flex", gap:"0.5rem", flexWrap:"wrap" }}>\n            {resultado.top_clases.map(c => (\n              <span key={c.clase} style={{\n                background:"rgba(0,0,0,0.06)", borderRadius:"6px",\n                padding:"0.2rem 0.6rem", fontSize:"0.78rem",\n              }}>\n                {c.clase} {(c.probabilidad * 100).toFixed(0)}%\n              </span>\n            ))}\n          </div>\n\n          <hr style={{ border:"none", borderTop:`1px solid ${col.borde}`, margin:"0.8rem 0" }} />\n          <p style={{ margin:0, fontSize:"0.85rem", lineHeight:1.7 }}>\n            <strong>Recomendacion:</strong><br />{resultado.recomendacion}\n          </p>\n        </div>\n      )}\n    </div>\n  );\n}\n\n// ── Componente principal ─────────────────────────────────────\n\nexport default function InteligenciaArtificial() {\n  // BUG-011 FIX: leer cultivoId desde sessionStorage en lugar de hardcodearlo.\n  // Cultivos.jsx escribe "gv_cultivo_activo" al seleccionar un cultivo.\n  const [cultivoId,  setCultivoId]  = useState(() => {\n    const stored = sessionStorage.getItem("gv_cultivo_activo");\n    return stored ? parseInt(stored, 10) : null;\n  });\n  const [cultivoNombre, setCultivoNombre] = useState(\n    () => sessionStorage.getItem("gv_cultivo_nombre") || ""\n  );\n  const [resumen,  setResumen]  = useState(null);\n  const [cargando, setCargando] = useState(true);\n\n  // Estados de cada modelo\n  const [fito,    setFito]    = useState(null);\n  const [riego,   setRiego]   = useState(null);\n  const [fert,    setFert]    = useState(null);\n  const [loadF,   setLoadF]   = useState(false);\n  const [loadR,   setLoadR]   = useState(false);\n  const [loadFe,  setLoadFe]  = useState(false);\n  const [errF,    setErrF]    = useState("");\n  const [errR,    setErrR]    = useState("");\n  const [errFe,   setErrFe]   = useState("");\n\n  const [tabActiva, setTabActiva] = useState("enfermedades");\n\n  useEffect(() => {\n    iaService.resumen(cultivoId)\n      .then(setResumen)\n      .catch(() => {})\n      .finally(() => setCargando(false));\n  }, []);\n\n  const ejecutarFito = async () => {\n    setLoadF(true); setErrF("");\n    try { setFito(await iaService.predecirFitosanitario(cultivoId)); }\n    catch(e) { setErrF(e.message); }\n    finally { setLoadF(false); }\n  };\n\n  const ejecutarRiego = async () => {\n    setLoadR(true); setErrR("");\n    try { setRiego(await iaService.recomendarRiego(cultivoId)); }\n    catch(e) { setErrR(e.message); }\n    finally { setLoadR(false); }\n  };\n\n  const ejecutarFert = async () => {\n    setLoadFe(true); setErrFe("");\n    try { setFert(await iaService.recomendarFertilizacion(cultivoId)); }\n    catch(e) { setErrFe(e.message); }\n    finally { setLoadFe(false); }\n  };\n\n  // ── Renderizado de cada resultado ──────────────────────────\n\n  const datosFito = fito && (\n    <div>\n      <p style={{ margin:"0 0 0.4rem" }}>\n        {RIESGO_ICONO[fito.nivel_riesgo]} Nivel de riesgo:{" "}\n        <strong>{fito.nivel_riesgo.toUpperCase()}</strong> — {fito.probabilidad_pct}\n      </p>\n      {fito.factores_riesgo.map((f, i) => (\n        <p key={i} style={{ margin:"0.15rem 0", fontSize:"0.82rem", color:"#7a5c3a" }}>\n          · {f}\n        </p>\n      ))}\n      <hr style={{ border:"none", borderTop:`1px solid ${C.borde}`, margin:"0.8rem 0" }} />\n      <p style={{ margin:0 }}><strong>Recomendacion:</strong><br />{fito.recomendacion}</p>\n    </div>\n  );\n\n  const datosRiego = riego && (\n    <div>\n      <p style={{ margin:"0 0 0.4rem" }}>\n        Necesita riego:{" "}\n        <strong style={{ color: riego.necesita_riego === "si" ? C.rojo : C.verde }}>\n          {riego.necesita_riego.toUpperCase()}\n        </strong>\n        {riego.cantidad_litros_m2 && ` — ${riego.cantidad_litros_m2} L/m²`}\n        {riego.frecuencia_dias    && ` — cada ${riego.frecuencia_dias} dia(s)`}\n      </p>\n      <p style={{ margin:"0.3rem 0", fontSize:"0.82rem", color:"#7a5c3a" }}>\n        {riego.justificacion}\n      </p>\n      <hr style={{ border:"none", borderTop:`1px solid ${C.borde}`, margin:"0.8rem 0" }} />\n      <p style={{ margin:0 }}><strong>Accion:</strong><br />{riego.recomendacion}</p>\n    </div>\n  );\n\n  const datosFert = fert && (\n    <div>\n      <p style={{ margin:"0 0 0.4rem" }}>\n        Fertilizante: <strong>{fert.tipo_fertilizante}</strong>\n      </p>\n      {fert.dosis_kg_ha && (\n        <p style={{ margin:"0 0 0.25rem", fontSize:"0.83rem" }}>\n          Dosis: {fert.dosis_kg_ha} kg/ha · {fert.frecuencia_aplicacion}\n        </p>\n      )}\n      {fert.nutrientes_deficientes.length > 0 && (\n        <p style={{ margin:"0 0 0.5rem", fontSize:"0.82rem", color:"#7a5c3a" }}>\n          Deficiencias: {fert.nutrientes_deficientes.join(", ")}\n        </p>\n      )}\n      <hr style={{ border:"none", borderTop:`1px solid ${C.borde}`, margin:"0.8rem 0" }} />\n      <p style={{ margin:0 }}><strong>Plan:</strong><br />{fert.recomendacion}</p>\n    </div>\n  );\n\n  if (!cultivoId) return (\n    <div style={{ padding: "2rem", textAlign: "center", color: "#6f3a1b" }}>\n      <p style={{ fontSize: "1.1rem", fontWeight: 600 }}>⚠️ No hay cultivo seleccionado</p>\n      <p style={{ color: "#9a7a5a" }}>\n        Ve al módulo <strong>Cultivos</strong> y selecciona un cultivo para continuar.\n      </p>\n    </div>\n  );\n  if (cargando) return (\n    <div style={estilos.contenedor}>\n      <p style={{ textAlign:"center", color:C.cafeCla, padding:"3rem" }}>\n        Cargando modulo de IA...\n      </p>\n    </div>\n  );\n\n  // ── Render principal ───────────────────────────────────────\n  const TABS = [\n    { id:"enfermedades",   label:"🍃 Enfermedades" },\n    { id:"plagas",         label:"🐛 Plagas"        },\n    { id:"prediccion",     label:"🌦️ Riesgo"        },\n    { id:"riego",          label:"💧 Riego"         },\n    { id:"fertilizacion",  label:"🌿 Fertilización" },\n  ];\n\n  return (\n    <div style={estilos.contenedor}>\n      {/* Encabezado */}\n      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>\n        <div>\n          <h1 style={{ margin:0, fontSize:"1.8rem", fontWeight:800, color:C.cafe }}>\n            🤖 Inteligencia Artificial\n          </h1>\n          <p style={{ margin:0, color:"#7a5c3a" }}>GranoVital IA — {cultivoNombre || `Cultivo #${cultivoId}`}</p>\n        </div>\n      </div>\n\n      {/* Banner RN-03 */}\n      <BannerRN03 validez={resumen} />\n\n      {/* Alertas del resumen */}\n      {resumen?.alertas?.length > 0 && (\n        <div style={{\n          background:"#fff7ed", border:`1px solid #ea580c`,\n          borderRadius:"12px", padding:"1rem 1.4rem",\n        }}>\n          <p style={{ margin:"0 0 0.5rem", fontWeight:700, color:"#ea580c" }}>\n            Alertas activas ({resumen.alertas.length})\n          </p>\n          {resumen.alertas.map((a, i) => (\n            <p key={i} style={{ margin:"0.2rem 0", fontSize:"0.85rem", color:"#7a5c3a" }}>\n              ⚠ {a}\n            </p>\n          ))}\n        </div>\n      )}\n\n      {/* Tabs */}\n      <div style={{\n        display:"flex", gap:0,\n        borderBottom:`2px solid ${C.borde}`,\n        overflowX:"auto",\n      }}>\n        {TABS.map(t => (\n          <button key={t.id} onClick={() => setTabActiva(t.id)}\n            style={{\n              padding:"0.6rem 1.2rem", border:"none", background:"none",\n              fontWeight: tabActiva === t.id ? 800 : 400,\n              color:      tabActiva === t.id ? C.cafe : "#9a7a5a",\n              borderBottom: tabActiva === t.id\n                ? `3px solid ${C.cafe}` : "3px solid transparent",\n              cursor:"pointer", fontSize:"0.88rem",\n              marginBottom:"-2px", whiteSpace:"nowrap",\n            }}>\n            {t.label}\n          </button>\n        ))}\n      </div>\n\n      {/* Contenido de cada tab */}\n      <div style={{ minHeight:"300px" }}>\n        {tabActiva === "enfermedades" && (\n          <div>\n            <p style={{ color:"#7a5c3a", fontSize:"0.88rem", marginBottom:"1rem" }}>\n              RF-05: suba una foto de una hoja de cafe para detectar Roya,\n              Mancha de Hierro, Antracnosis o CBD.\n            </p>\n            <PanelImagen tipo="enfermedad" cultivoId={cultivoId} />\n          </div>\n        )}\n\n        {tabActiva === "plagas" && (\n          <div>\n            <p style={{ color:"#7a5c3a", fontSize:"0.88rem", marginBottom:"1rem" }}>\n              RF-06: suba una foto del cultivo o fruto para identificar Broca,\n              Minador de la Hoja, Trips o Acaro Rojo.\n            </p>\n            <PanelImagen tipo="plaga" cultivoId={cultivoId} />\n          </div>\n        )}\n\n        {tabActiva === "prediccion" && (\n          <TarjetaResultado\n            titulo="Prediccion de Riesgo Fitosanitario"\n            icono="🌦️"\n            datos={datosFito}\n            cargando={loadF}\n            error={errF}\n            urgencia={fito?.nivel_riesgo}\n            onAccion={ejecutarFito}\n            textoAccion="Predecir riesgo ahora"\n          />\n        )}\n\n        {tabActiva === "riego" && (\n          <TarjetaResultado\n            titulo="Recomendacion de Riego"\n            icono="💧"\n            datos={datosRiego}\n            cargando={loadR}\n            error={errR}\n            urgencia={riego?.nivel_urgencia}\n            onAccion={ejecutarRiego}\n            textoAccion="Evaluar necesidad de riego"\n          />\n        )}\n\n        {tabActiva === "fertilizacion" && (\n          <TarjetaResultado\n            titulo="Plan de Fertilizacion"\n            icono="🌿"\n            datos={datosFert}\n            cargando={loadFe}\n            error={errFe}\n            urgencia={fert?.nivel_urgencia}\n            onAccion={ejecutarFert}\n            textoAccion="Generar plan de fertilizacion"\n          />\n        )}\n      </div>\n    </div>\n  );\n}\n\nconst estilos = {\n  contenedor: {\n    minHeight:"100vh", background:C.gris, padding:"2rem",\n    fontFamily:"\'Segoe UI\', Roboto, sans-serif", color:C.texto,\n    display:"flex", flexDirection:"column", gap:"1.5rem",\n  },\n};\n'

ARCHIVOS["frontend/src/pages/Monitoreo.jsx"] = '// ==============================================================\n// modulo_03_monitoreo / frontend/src/pages/Monitoreo.jsx\n// Dashboard de Monitoreo Ambiental y Suelo\n//\n// RF-03  Visualiza variables ambientales en tiempo real\n// RF-04  Visualiza estado del suelo con interpretacion\n// RN-03  Indicador de validez de datos para IA\n// RNF-02 Usabilidad para usuarios sin perfil tecnico\n// RNF-07 Responsive - funciona en web y movil\n// ==============================================================\n\nimport { useState } from "react";\nimport { useMonitoreo, useHistorialAmbiental, useHistorialSuelo } from "../hooks/useMonitoreo";\nimport FormularioAmbiental from "../components/FormularioAmbiental";\nimport FormularioSuelo     from "../components/FormularioSuelo";\n\n// ==============================================================\n// CONSTANTES DE DISENO\n// ==============================================================\nconst COLOR = {\n  cafe:     "#6f3a1b",\n  cafeCla:  "#a0522d",\n  verde:    "#2d7a3a",\n  amarillo: "#c8a000",\n  rojo:     "#b91c1c",\n  azul:     "#0284c7",\n  gris:     "#f5f0eb",\n  borde:    "#d4b896",\n  texto:    "#1a0e05",\n};\n\n// ==============================================================\n// SUBCOMPONENTES\n// ==============================================================\n\nfunction Modal({ abierto, titulo, onCerrar, children }) {\n  if (!abierto) return null;\n  return (\n    <div style={{\n      position: "fixed", inset: 0, background: "rgba(0,0,0,0.4)",\n      display: "flex", alignItems: "center", justifyContent: "center",\n      zIndex: 1000, padding: "1rem",\n    }}>\n      <div style={{\n        background: "#fff", borderRadius: "16px", padding: "2rem",\n        width: "100%", maxWidth: "540px", maxHeight: "90vh",\n        overflowY: "auto", boxShadow: "0 20px 60px rgba(0,0,0,0.3)",\n      }}>\n        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1.5rem" }}>\n          <h3 style={{ margin: 0, color: COLOR.cafe }}>{titulo}</h3>\n          <button onClick={onCerrar}\n            style={{ background: "none", border: "none", fontSize: "1.4rem", cursor: "pointer" }}>\n            x\n          </button>\n        </div>\n        {children}\n      </div>\n    </div>\n  );\n}\n\nfunction TarjetaMetrica({ icono, etiqueta, valor, unidad, estado = "normal" }) {\n  const colores = {\n    normal:   { bg: "#fff",     borde: COLOR.borde,   texto: COLOR.cafe  },\n    alerta:   { bg: "#fffbeb",  borde: COLOR.amarillo, texto: COLOR.amarillo },\n    critico:  { bg: "#fff1f0",  borde: COLOR.rojo,    texto: COLOR.rojo  },\n    optimo:   { bg: "#f0fdf4",  borde: COLOR.verde,   texto: COLOR.verde },\n  };\n  const c = colores[estado] || colores.normal;\n  return (\n    <div style={{\n      background: c.bg, border: `1.5px solid ${c.borde}`,\n      borderRadius: "12px", padding: "1rem 1.2rem",\n      display: "flex", alignItems: "center", gap: "0.8rem",\n    }}>\n      <span style={{ fontSize: "1.8rem" }}>{icono}</span>\n      <div>\n        <p style={{ margin: 0, fontSize: "0.78rem", color: "#7a5c3a", fontWeight: 600 }}>\n          {etiqueta}\n        </p>\n        <p style={{ margin: 0, fontSize: "1.5rem", fontWeight: 800, color: c.texto }}>\n          {valor !== null && valor !== undefined ? `${valor}` : "-"}\n          {valor !== null && valor !== undefined && unidad && (\n            <span style={{ fontSize: "0.85rem", fontWeight: 400 }}> {unidad}</span>\n          )}\n        </p>\n      </div>\n    </div>\n  );\n}\n\nfunction BannerValidez({ validez }) {\n  if (!validez) return null;\n  const esValido = validez.ambos_validos;\n  return (\n    <div style={{\n      background:   esValido ? "#f0fdf4" : "#fffbeb",\n      border:       `1.5px solid ${esValido ? COLOR.verde : COLOR.amarillo}`,\n      borderRadius: "12px",\n      padding:      "1rem 1.4rem",\n      display:      "flex",\n      alignItems:   "center",\n      gap:          "0.8rem",\n    }}>\n      <span style={{ fontSize: "1.5rem" }}>{esValido ? "✅" : "⚠️"}</span>\n      <div>\n        <p style={{ margin: 0, fontWeight: 700, color: esValido ? COLOR.verde : COLOR.amarillo }}>\n          {esValido\n            ? "Datos actualizados - IA habilitada"\n            : "Datos desactualizados - IA no disponible"}\n        </p>\n        <p style={{ margin: "0.2rem 0 0", fontSize: "0.83rem", color: "#7a5c3a" }}>\n          {validez.mensaje}\n        </p>\n      </div>\n      <div style={{ marginLeft: "auto", textAlign: "right", fontSize: "0.78rem", color: "#9a7a5a" }}>\n        <p style={{ margin: 0 }}>Amb: {\n          validez.horas_desde_ambiental\n            ? `hace ${validez.horas_desde_ambiental.toFixed(1)} h`\n            : "Sin datos"\n        }</p>\n        <p style={{ margin: 0 }}>Suelo: {\n          validez.horas_desde_suelo\n            ? `hace ${validez.horas_desde_suelo.toFixed(1)} h`\n            : "Sin datos"\n        }</p>\n      </div>\n    </div>\n  );\n}\n\nfunction FilaHistorial({ fecha, origen, variables }) {\n  const etiquetaOrigen = {\n    manual:      "Manual",\n    sensor_iot:  "Sensor IoT",\n    laboratorio: "Laboratorio",\n    api_externa: "API ext.",\n  };\n  return (\n    <div style={{\n      border: `1px solid ${COLOR.borde}`,\n      borderRadius: "8px",\n      padding: "0.75rem 1rem",\n      background: "#fafaf8",\n      display: "flex",\n      justifyContent: "space-between",\n      alignItems: "center",\n      gap: "1rem",\n    }}>\n      <div style={{ fontSize: "0.8rem", color: "#9a7a5a" }}>\n        <p style={{ margin: 0, fontWeight: 600 }}>\n          {new Date(fecha).toLocaleDateString("es-CO", {\n            day: "2-digit", month: "short", year: "numeric",\n            hour: "2-digit", minute: "2-digit",\n          })}\n        </p>\n        <span style={{\n          background: "#e8ddd4", color: COLOR.cafe,\n          borderRadius: "4px", padding: "1px 6px", fontSize: "0.73rem",\n        }}>\n          {etiquetaOrigen[origen] || origen}\n        </span>\n      </div>\n      <div style={{ display: "flex", gap: "1.5rem", flexWrap: "wrap" }}>\n        {variables.map(({ etiqueta, valor, unidad }) =>\n          valor !== null && valor !== undefined ? (\n            <div key={etiqueta} style={{ textAlign: "center" }}>\n              <p style={{ margin: 0, fontSize: "0.73rem", color: "#9a7a5a" }}>{etiqueta}</p>\n              <p style={{ margin: 0, fontSize: "0.92rem", fontWeight: 700, color: COLOR.cafe }}>\n                {valor} <span style={{ fontWeight: 400, fontSize: "0.78rem" }}>{unidad}</span>\n              </p>\n            </div>\n          ) : null\n        )}\n      </div>\n    </div>\n  );\n}\n\n// ==============================================================\n// DETERMINACION DE ESTADO DE ALERTA DE UNA METRICA\n// ==============================================================\nfunction estadoTemp(v) {\n  if (v === null || v === undefined) return "normal";\n  if (v < 14 || v > 30) return "critico";\n  if (v < 18 || v > 24) return "alerta";\n  return "optimo";\n}\nfunction estadoHumRel(v) {\n  if (v === null || v === undefined) return "normal";\n  if (v < 55 || v > 95) return "critico";\n  if (v < 70 || v > 90) return "alerta";\n  return "optimo";\n}\nfunction estadoPH(v) {\n  if (v === null || v === undefined) return "normal";\n  if (v < 4.5 || v > 7.5) return "critico";\n  if (v < 5.5 || v > 6.5) return "alerta";\n  return "optimo";\n}\n\n// ==============================================================\n// COMPONENTE PRINCIPAL\n// ==============================================================\n\nexport default function Monitoreo() {\n  // BUG-011 FIX: leer cultivoId desde sessionStorage en lugar de hardcodearlo.\n  // Cultivos.jsx escribe "gv_cultivo_activo" al seleccionar un cultivo.\n  const cultivoId    = sessionStorage.getItem("gv_cultivo_activo")\n    ? parseInt(sessionStorage.getItem("gv_cultivo_activo"), 10)\n    : null;\n  const cultivoNombre = sessionStorage.getItem("gv_cultivo_nombre") || "Mi Cultivo";\n\n  const { resumen, validez, cargando, error, recargar } = useMonitoreo(cultivoId, 60);\n  const { historial: histAmb, recargar: recargarAmb }   = useHistorialAmbiental(cultivoId, 15);\n  const { historial: histSue, recargar: recargarSue }   = useHistorialSuelo(cultivoId, 15);\n\n  const [modalAmb,    setModalAmb]    = useState(false);\n  const [modalSuelo,  setModalSuelo]  = useState(false);\n  const [tabActiva,   setTabActiva]   = useState("ambiental");\n\n  const alGuardarAmb = () => {\n    setModalAmb(false);\n    recargar();\n    recargarAmb();\n  };\n  const alGuardarSuelo = () => {\n    setModalSuelo(false);\n    recargar();\n    recargarSue();\n  };\n\n  // ==============================================================\n  // RENDER\n  // ==============================================================\n\n  if (cargando && !resumen) {\n    return (\n      <div style={estilos.contenedor}>\n        <p style={{ textAlign: "center", color: COLOR.cafeCla, padding: "3rem" }}>\n          Cargando datos de monitoreo...\n        </p>\n      </div>\n    );\n  }\n\n  if (!cultivoId) return (\n    <div style={{ padding: "2rem", textAlign: "center", color: "#6f3a1b" }}>\n      <p style={{ fontSize: "1.1rem", fontWeight: 600 }}>⚠️ No hay cultivo seleccionado</p>\n      <p style={{ color: "#9a7a5a" }}>\n        Ve al módulo <strong>Cultivos</strong> y selecciona un cultivo para continuar.\n      </p>\n    </div>\n  );\n  return (\n    <div style={estilos.contenedor}>\n\n      {/* Encabezado */}\n      <div style={estilos.encabezado}>\n        <div>\n          <h1 style={estilos.titulo}>🌡️ Monitoreo</h1>\n          <p style={{ margin: 0, color: "#7a5c3a" }}>{cultivoNombre}</p>\n        </div>\n        <div style={{ display: "flex", gap: "0.8rem" }}>\n          <button onClick={() => setModalAmb(true)} style={estilos.botonVerde}>\n            + Ambiental\n          </button>\n          <button onClick={() => setModalSuelo(true)} style={estilos.botonCafe}>\n            + Suelo\n          </button>\n        </div>\n      </div>\n\n      {/* Error global */}\n      {error && (\n        <div style={estilos.alerta} role="alert">{error}</div>\n      )}\n\n      {/* Banner de validez RN-03 */}\n      <BannerValidez validez={validez} />\n\n      {/* Alertas activas */}\n      {resumen?.alertas?.length > 0 && (\n        <div style={{\n          background: "#fffbeb", border: `1px solid ${COLOR.amarillo}`,\n          borderRadius: "12px", padding: "1rem 1.4rem",\n        }}>\n          <p style={{ margin: "0 0 0.5rem", fontWeight: 700, color: COLOR.amarillo }}>\n            Alertas activas ({resumen.alertas.length})\n          </p>\n          {resumen.alertas.map((a, i) => (\n            <p key={i} style={{ margin: "0.25rem 0", fontSize: "0.85rem", color: "#7a5c3a" }}>\n              - {a}\n            </p>\n          ))}\n        </div>\n      )}\n\n      {/* Metricas ambientales */}\n      <section>\n        <h2 style={estilos.seccion}>Variables Ambientales</h2>\n        <div style={estilos.gridMetricas}>\n          <TarjetaMetrica\n            icono="🌡️" etiqueta="Temperatura"\n            valor={resumen?.ultima_temperatura}\n            unidad="C"\n            estado={estadoTemp(resumen?.ultima_temperatura)}\n          />\n          <TarjetaMetrica\n            icono="💧" etiqueta="Humedad relativa"\n            valor={resumen?.ultima_humedad_rel}\n            unidad="%"\n            estado={estadoHumRel(resumen?.ultima_humedad_rel)}\n          />\n          <TarjetaMetrica\n            icono="🌧️" etiqueta="Precipitacion"\n            valor={resumen?.ultima_precipitacion}\n            unidad="mm"\n          />\n        </div>\n      </section>\n\n      {/* Metricas de suelo */}\n      <section>\n        <h2 style={estilos.seccion}>Estado del Suelo</h2>\n        <div style={estilos.gridMetricas}>\n          <TarjetaMetrica\n            icono="🧪" etiqueta="pH del suelo"\n            valor={resumen?.ultimo_ph}\n            estado={estadoPH(resumen?.ultimo_ph)}\n          />\n          <TarjetaMetrica\n            icono="💦" etiqueta="Humedad suelo"\n            valor={resumen?.ultima_humedad_suelo}\n            unidad="%"\n          />\n          <TarjetaMetrica\n            icono="🌿" etiqueta="Nitrogeno"\n            valor={resumen?.ultimo_nitrogeno}\n            unidad="mg/kg"\n            estado={\n              resumen?.ultimo_nitrogeno !== null && resumen?.ultimo_nitrogeno < 20\n                ? "alerta" : "normal"\n            }\n          />\n        </div>\n      </section>\n\n      {/* Historial con tabs */}\n      <section>\n        <div style={{ display: "flex", gap: 0, borderBottom: `2px solid ${COLOR.borde}`, marginBottom: "1rem" }}>\n          {["ambiental", "suelo"].map(tab => (\n            <button\n              key={tab}\n              onClick={() => setTabActiva(tab)}\n              style={{\n                padding:    "0.6rem 1.5rem",\n                border:     "none",\n                background: "none",\n                fontWeight: tabActiva === tab ? 800 : 400,\n                color:      tabActiva === tab ? COLOR.cafe : "#9a7a5a",\n                borderBottom: tabActiva === tab ? `3px solid ${COLOR.cafe}` : "3px solid transparent",\n                cursor:     "pointer",\n                fontSize:   "0.92rem",\n                marginBottom: "-2px",\n              }}\n            >\n              {tab === "ambiental" ? "Historial Ambiental" : "Historial Suelo"}\n            </button>\n          ))}\n        </div>\n\n        {tabActiva === "ambiental" && (\n          <div style={{ display: "flex", flexDirection: "column", gap: "0.6rem" }}>\n            {histAmb.length === 0 ? (\n              <p style={{ color: "#bbb", fontSize: "0.9rem" }}>\n                Sin lecturas ambientales registradas.\n              </p>\n            ) : (\n              histAmb.map(r => (\n                <FilaHistorial\n                  key={r.id_monitoreo}\n                  fecha={r.fecha_registro}\n                  origen={r.origen_dato}\n                  variables={[\n                    { etiqueta: "Temp",    valor: r.temperatura,       unidad: "C"    },\n                    { etiqueta: "Hum",     valor: r.humedad_relativa,  unidad: "%"    },\n                    { etiqueta: "Lluvia",  valor: r.precipitacion_mm,  unidad: "mm"   },\n                    { etiqueta: "Rad",     valor: r.radiacion_solar,   unidad: "W/m2" },\n                    { etiqueta: "Viento",  valor: r.velocidad_viento,  unidad: "km/h" },\n                  ]}\n                />\n              ))\n            )}\n          </div>\n        )}\n\n        {tabActiva === "suelo" && (\n          <div style={{ display: "flex", flexDirection: "column", gap: "0.6rem" }}>\n            {histSue.length === 0 ? (\n              <p style={{ color: "#bbb", fontSize: "0.9rem" }}>\n                Sin lecturas de suelo registradas.\n              </p>\n            ) : (\n              histSue.map(r => (\n                <FilaHistorial\n                  key={r.id_monitoreo_suelo}\n                  fecha={r.fecha_registro}\n                  origen={r.origen_dato}\n                  variables={[\n                    { etiqueta: "pH",   valor: r.ph,               unidad: ""       },\n                    { etiqueta: "Hum",  valor: r.humedad_suelo,    unidad: "%"      },\n                    { etiqueta: "N",    valor: r.nitrogeno,        unidad: "mg/kg"  },\n                    { etiqueta: "P",    valor: r.fosforo,          unidad: "mg/kg"  },\n                    { etiqueta: "K",    valor: r.potasio,          unidad: "mg/kg"  },\n                    { etiqueta: "M.O.", valor: r.materia_organica, unidad: "%"      },\n                  ]}\n                />\n              ))\n            )}\n          </div>\n        )}\n      </section>\n\n      {/* Modal - Ambiental */}\n      <Modal abierto={modalAmb} titulo="Registrar lectura ambiental" onCerrar={() => setModalAmb(false)}>\n        <FormularioAmbiental\n          cultivoId={cultivoId}\n          onGuardado={alGuardarAmb}\n          onCancelar={() => setModalAmb(false)}\n        />\n      </Modal>\n\n      {/* Modal - Suelo */}\n      <Modal abierto={modalSuelo} titulo="Registrar analisis de suelo" onCerrar={() => setModalSuelo(false)}>\n        <FormularioSuelo\n          cultivoId={cultivoId}\n          onGuardado={alGuardarSuelo}\n          onCancelar={() => setModalSuelo(false)}\n        />\n      </Modal>\n    </div>\n  );\n}\n\n// ==============================================================\n// ESTILOS\n// ==============================================================\n\nconst estilos = {\n  contenedor: {\n    minHeight:  "100vh",\n    background: COLOR.gris,\n    padding:    "2rem",\n    fontFamily: "\'Segoe UI\', Roboto, sans-serif",\n    color:      COLOR.texto,\n    display:    "flex",\n    flexDirection: "column",\n    gap:        "1.5rem",\n  },\n  encabezado: {\n    display:        "flex",\n    justifyContent: "space-between",\n    alignItems:     "center",\n  },\n  titulo: {\n    margin: 0, fontSize: "1.8rem",\n    fontWeight: 800, color: COLOR.cafe,\n  },\n  seccion: {\n    margin: "0 0 0.8rem",\n    fontSize: "1rem",\n    fontWeight: 700,\n    color: COLOR.cafe,\n    borderBottom: `2px solid ${COLOR.borde}`,\n    paddingBottom: "0.4rem",\n  },\n  gridMetricas: {\n    display:             "grid",\n    gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",\n    gap:                 "1rem",\n  },\n  alerta: {\n    background: "#fff1f0", border: "1px solid #ffccc7",\n    borderRadius: "8px", padding: "0.8rem 1rem",\n    color: COLOR.rojo, fontSize: "0.87rem",\n  },\n  botonVerde: {\n    padding: "0.6rem 1.2rem", borderRadius: "8px",\n    border: "none", background: "#dcfce7",\n    color: COLOR.verde, fontWeight: 700, cursor: "pointer",\n  },\n  botonCafe: {\n    padding: "0.6rem 1.2rem", borderRadius: "8px",\n    border: "none",\n    background: "linear-gradient(135deg, #6f3a1b, #a0522d)",\n    color: "#fff", fontWeight: 700, cursor: "pointer",\n  },\n};\n'

ARCHIVOS["frontend/src/pages/Cultivos.jsx"] = '// ==============================================================\n// modulo_02_cultivos / frontend/src/pages/Cultivos.jsx\n// Vista principal de Gestion de Cultivos y Lotes\n// RF-03 Cultivos | RF-04 Lotes | RNF-02 Usabilidad\n// RNF-07 Funciona en web y movil (responsive)\n// ==============================================================\n\nimport { useState, useEffect, useCallback } from "react";\nimport { cultivoService, loteService } from "../services/cultivoService";\n\n// Paleta de colores GranoVital\nconst COLOR = {\n  cafe:      "#6f3a1b",\n  cafeCLaro: "#a0522d",\n  verde:     "#2d7a3a",\n  amarillo:  "#c8a000",\n  rojo:      "#b91c1c",\n  gris:      "#f5f0eb",\n  texto:     "#1a0e05",\n  borde:     "#d4b896",\n};\n\n// Etiquetas de estado del Cultivo (diagrama de estados)\nconst ESTADO_CULTIVO = {\n  creado:                  { texto: "Creado",             color: COLOR.amarillo },\n  en_seguimiento:          { texto: "En Seguimiento",     color: COLOR.verde    },\n  con_problema_detectado:  { texto: "Con Problema",       color: COLOR.rojo     },\n  tratamiento_aplicado:    { texto: "En Tratamiento",     color: "#7c3aed"      },\n  finalizado:              { texto: "Finalizado",         color: "#64748b"      },\n  eliminado:               { texto: "Eliminado",          color: "#94a3b8"      },\n};\n\n// Etiquetas de estado del Lote (diagrama de estados)\nconst ESTADO_LOTE = {\n  registrado:  { texto: "Registrado",  color: COLOR.amarillo },\n  disponible:  { texto: "Disponible",  color: "#0284c7"      },\n  en_analisis: { texto: "En Analisis", color: "#7c3aed"      },\n  aprobado:    { texto: "Aprobado",    color: COLOR.verde    },\n  con_problema:{ texto: "Con Problema",color: COLOR.rojo     },\n  vendido:     { texto: "Vendido",     color: "#64748b"      },\n  eliminado:   { texto: "Eliminado",   color: "#94a3b8"      },\n};\n\n// ==============================================================\n// COMPONENTES REUTILIZABLES\n// ==============================================================\n\nfunction Badge({ estado, mapa }) {\n  const cfg = mapa[estado] || { texto: estado, color: "#94a3b8" };\n  return (\n    <span style={{\n      background:   cfg.color + "22",\n      color:        cfg.color,\n      border:       `1px solid ${cfg.color}55`,\n      borderRadius: "20px",\n      padding:      "3px 10px",\n      fontSize:     "0.78rem",\n      fontWeight:   700,\n    }}>\n      {cfg.texto}\n    </span>\n  );\n}\n\nfunction Tarjeta({ titulo, valor, icono, color }) {\n  return (\n    <div style={{\n      background:   "#fff",\n      border:       `1px solid ${COLOR.borde}`,\n      borderRadius: "12px",\n      padding:      "1.2rem 1.5rem",\n      display:      "flex",\n      alignItems:   "center",\n      gap:          "1rem",\n    }}>\n      <span style={{ fontSize: "2rem" }}>{icono}</span>\n      <div>\n        <p style={{ margin: 0, color: "#7a5c3a", fontSize: "0.8rem", fontWeight: 600 }}>\n          {titulo}\n        </p>\n        <p style={{ margin: 0, fontSize: "1.8rem", fontWeight: 800, color: color || COLOR.cafe }}>\n          {valor}\n        </p>\n      </div>\n    </div>\n  );\n}\n\nfunction Modal({ abierto, titulo, onCerrar, children }) {\n  if (!abierto) return null;\n  return (\n    <div style={{\n      position:   "fixed", inset: 0,\n      background: "rgba(0,0,0,0.4)",\n      display:    "flex",\n      alignItems: "center",\n      justifyContent: "center",\n      zIndex:     1000,\n      padding:    "1rem",\n    }}>\n      <div style={{\n        background:   "#fff",\n        borderRadius: "16px",\n        padding:      "2rem",\n        width:        "100%",\n        maxWidth:     "520px",\n        maxHeight:    "90vh",\n        overflowY:    "auto",\n        boxShadow:    "0 20px 60px rgba(0,0,0,0.3)",\n      }}>\n        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1.5rem" }}>\n          <h3 style={{ margin: 0, color: COLOR.cafe }}>{titulo}</h3>\n          <button\n            onClick={onCerrar}\n            style={{ background: "none", border: "none", fontSize: "1.5rem", cursor: "pointer" }}\n            aria-label="Cerrar modal"\n          >\n            x\n          </button>\n        </div>\n        {children}\n      </div>\n    </div>\n  );\n}\n\nfunction Campo({ label, name, value, onChange, type = "text", required = false, placeholder = "" }) {\n  return (\n    <div style={{ display: "flex", flexDirection: "column", gap: "0.3rem" }}>\n      <label style={{ fontSize: "0.83rem", fontWeight: 600, color: "#4a2c0a" }}>\n        {label}{required && " *"}\n      </label>\n      <input\n        name={name}\n        type={type}\n        value={value}\n        onChange={onChange}\n        required={required}\n        placeholder={placeholder}\n        style={{\n          padding: "0.6rem 0.9rem",\n          border: `1.5px solid ${COLOR.borde}`,\n          borderRadius: "8px",\n          fontSize: "0.9rem",\n          outline: "none",\n        }}\n      />\n    </div>\n  );\n}\n\nfunction Boton({ onClick, children, variante = "primario", tipo = "button", desactivado = false }) {\n  const estilosBase = {\n    padding:      "0.6rem 1.2rem",\n    borderRadius: "8px",\n    border:       "none",\n    fontSize:     "0.9rem",\n    fontWeight:   700,\n    cursor:       desactivado ? "not-allowed" : "pointer",\n    opacity:      desactivado ? 0.6 : 1,\n    transition:   "opacity 0.2s",\n  };\n\n  const variantes = {\n    primario:  { background: COLOR.cafe,      color: "#fff"     },\n    secundario:{ background: "#f5f0eb",        color: COLOR.cafe, border: `1px solid ${COLOR.borde}` },\n    peligro:   { background: "#fee2e2",        color: COLOR.rojo  },\n    verde:     { background: "#dcfce7",        color: COLOR.verde },\n  };\n\n  return (\n    <button\n      type={tipo}\n      onClick={onClick}\n      disabled={desactivado}\n      style={{ ...estilosBase, ...variantes[variante] }}\n    >\n      {children}\n    </button>\n  );\n}\n\n// ==============================================================\n// FORMULARIO CULTIVO\n// ==============================================================\n\nfunction FormularioCultivo({ onGuardar, onCancelar, inicial = {} }) {\n  const [form, setForm] = useState({\n    nombre_cultivo: inicial.nombre_cultivo || "",\n    ubicacion:      inicial.ubicacion      || "",\n    area_hectareas: inicial.area_hectareas || "",\n    variedad_cafe:  inicial.variedad_cafe  || "",\n    observaciones:  inicial.observaciones  || "",\n  });\n\n  const cambio = (e) => setForm(p => ({ ...p, [e.target.name]: e.target.value }));\n\n  const enviar = (e) => {\n    e.preventDefault();\n    onGuardar({\n      ...form,\n      area_hectareas: form.area_hectareas ? parseFloat(form.area_hectareas) : undefined,\n    });\n  };\n\n  return (\n    <form onSubmit={enviar} style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>\n      <Campo label="Nombre del cultivo" name="nombre_cultivo" value={form.nombre_cultivo}\n        onChange={cambio} required placeholder="Ej: Finca La Esperanza" />\n      <Campo label="Ubicacion" name="ubicacion" value={form.ubicacion}\n        onChange={cambio} placeholder="Ej: Andes, Antioquia - Coordenadas GPS" />\n      <Campo label="Area (hectareas)" name="area_hectareas" value={form.area_hectareas}\n        onChange={cambio} type="number" placeholder="Ej: 3.5" />\n      <Campo label="Variedad de cafe" name="variedad_cafe" value={form.variedad_cafe}\n        onChange={cambio} placeholder="Ej: Castillo, Caturra, Colombia" />\n      <Campo label="Observaciones" name="observaciones" value={form.observaciones}\n        onChange={cambio} placeholder="Informacion adicional del cultivo" />\n      <div style={{ display: "flex", gap: "0.8rem", justifyContent: "flex-end", marginTop: "0.5rem" }}>\n        <Boton variante="secundario" onClick={onCancelar}>Cancelar</Boton>\n        <Boton tipo="submit" variante="primario">Guardar</Boton>\n      </div>\n    </form>\n  );\n}\n\n// ==============================================================\n// FORMULARIO LOTE\n// ==============================================================\n\nfunction FormularioLote({ onGuardar, onCancelar }) {\n  const [form, setForm] = useState({\n    codigo_lote:   "",\n    cantidad_kg:   "",\n    fecha_cosecha: "",\n    observaciones: "",\n  });\n\n  const cambio = (e) => setForm(p => ({ ...p, [e.target.name]: e.target.value }));\n\n  const enviar = (e) => {\n    e.preventDefault();\n    onGuardar({\n      ...form,\n      codigo_lote: form.codigo_lote.toUpperCase(),\n      cantidad_kg: form.cantidad_kg ? parseFloat(form.cantidad_kg) : undefined,\n      // BUG-026 FIX: enviar fecha como string YYYY-MM-DD sin conversión UTC\n      fecha_cosecha: form.fecha_cosecha || undefined,\n    });\n  };\n\n  return (\n    <form onSubmit={enviar} style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>\n      <Campo label="Codigo del lote" name="codigo_lote" value={form.codigo_lote}\n        onChange={cambio} required placeholder="Ej: LOT-2025-001" />\n      <Campo label="Cantidad cosechada (kg)" name="cantidad_kg" value={form.cantidad_kg}\n        onChange={cambio} type="number" placeholder="Ej: 450" />\n      <Campo label="Fecha de cosecha" name="fecha_cosecha" value={form.fecha_cosecha}\n        onChange={cambio} type="date" />\n      <Campo label="Observaciones" name="observaciones" value={form.observaciones}\n        onChange={cambio} placeholder="Notas sobre la cosecha" />\n      <div style={{ display: "flex", gap: "0.8rem", justifyContent: "flex-end", marginTop: "0.5rem" }}>\n        <Boton variante="secundario" onClick={onCancelar}>Cancelar</Boton>\n        <Boton tipo="submit" variante="primario">Registrar Lote</Boton>\n      </div>\n    </form>\n  );\n}\n\n// ==============================================================\n// VISTA PRINCIPAL\n// ==============================================================\n\nexport default function Cultivos() {\n  const [resumen,        setResumen]        = useState(null);\n  const [cultivos,       setCultivos]       = useState([]);\n  const [lotes,          setLotes]          = useState([]);\n  const [cultivoActivo,  setCultivoActivo]  = useState(null);\n  const [cargando,       setCargando]       = useState(true);\n  const [error,          setError]          = useState("");\n  const [modalCultivo,   setModalCultivo]   = useState(false);\n  const [modalLote,      setModalLote]      = useState(false);\n  const [editando,       setEditando]       = useState(null);\n  const nombreUsuario    = localStorage.getItem("nombre") || "Caficultor";\n\n  // Carga inicial\n  const cargarDatos = useCallback(async () => {\n    setCargando(true);\n    setError("");\n    try {\n      const [res, cvs] = await Promise.all([\n        cultivoService.resumen(),\n        cultivoService.listar(),\n      ]);\n      setResumen(res);\n      setCultivos(cvs);\n      if (cvs.length > 0 && !cultivoActivo) {\n        setCultivoActivo(cvs[0]);\n        // BUG-011 FIX: persistir cultivo activo para IA y Monitoreo\n        sessionStorage.setItem("gv_cultivo_activo", cvs[0].id_cultivo);\n        sessionStorage.setItem("gv_cultivo_nombre", cvs[0].nombre_cultivo);\n        const ls = await loteService.listar(cvs[0].id_cultivo);\n        setLotes(ls);\n      }\n    } catch (e) {\n      setError(e.message);\n    } finally {\n      setCargando(false);\n    }\n  }, []);\n\n  useEffect(() => { cargarDatos(); }, [cargarDatos]);\n\n  const seleccionarCultivo = async (cultivo) => {\n    setCultivoActivo(cultivo);\n    // BUG-011 FIX: persistir cultivo activo para IA y Monitoreo\n    sessionStorage.setItem("gv_cultivo_activo", cultivo.id_cultivo);\n    sessionStorage.setItem("gv_cultivo_nombre", cultivo.nombre_cultivo);\n    const ls = await loteService.listar(cultivo.id_cultivo).catch(() => []);\n    setLotes(ls);\n  };\n\n  const guardarCultivo = async (datos) => {\n    try {\n      if (editando) {\n        await cultivoService.actualizar(editando.id_cultivo, datos);\n      } else {\n        await cultivoService.crear(datos);\n      }\n      setModalCultivo(false);\n      setEditando(null);\n      cargarDatos();\n    } catch (e) {\n      setError(e.message);\n    }\n  };\n\n  const guardarLote = async (datos) => {\n    if (!cultivoActivo) return;\n    try {\n      await loteService.crear(cultivoActivo.id_cultivo, datos);\n      setModalLote(false);\n      const ls = await loteService.listar(cultivoActivo.id_cultivo);\n      setLotes(ls);\n    } catch (e) {\n      setError(e.message);\n    }\n  };\n\n  // ==============================================================\n  // RENDER\n  // ==============================================================\n\n  if (cargando) {\n    return (\n      <div style={estilos.contenedor}>\n        <p style={{ textAlign: "center", color: COLOR.cafeCLaro, padding: "3rem" }}>\n          Cargando cultivos...\n        </p>\n      </div>\n    );\n  }\n\n  return (\n    <div style={estilos.contenedor}>\n\n      {/* Encabezado */}\n      <div style={estilos.encabezado}>\n        <div>\n          <h1 style={estilos.titulo}>☕ Mis Cultivos</h1>\n          <p style={{ margin: 0, color: "#7a5c3a" }}>Bienvenido, {nombreUsuario}</p>\n        </div>\n        <Boton onClick={() => { setEditando(null); setModalCultivo(true); }}>\n          + Nuevo Cultivo\n        </Boton>\n      </div>\n\n      {/* Error global */}\n      {error && (\n        <div style={estilos.alerta} role="alert">\n          {error}\n          <button onClick={() => setError("")} style={{ marginLeft: "1rem", cursor: "pointer" }}>\n            cerrar\n          </button>\n        </div>\n      )}\n\n      {/* Tarjetas de resumen */}\n      {resumen && (\n        <div style={estilos.gridResumen}>\n          <Tarjeta icono="🌱" titulo="Cultivos Activos"    valor={resumen.total_cultivos_activos} />\n          <Tarjeta icono="📦" titulo="Total Lotes"         valor={resumen.total_lotes} />\n          <Tarjeta icono="✅" titulo="Lotes Vendidos"      valor={resumen.lotes_vendidos}      color={COLOR.verde}   />\n          <Tarjeta icono="⚠️" titulo="Lotes con Problema" valor={resumen.lotes_con_problema}   color={COLOR.rojo}    />\n          <Tarjeta icono="🗺️" titulo="Area Total (ha)"    valor={resumen.area_total_hectareas.toFixed(1)} />\n        </div>\n      )}\n\n      {/* Cuerpo principal: lista cultivos + detalle lotes */}\n      <div style={estilos.gridPrincipal}>\n\n        {/* Lista de cultivos */}\n        <div style={estilos.panelIzq}>\n          <h3 style={estilos.subtitulo}>Cultivos registrados</h3>\n          {cultivos.length === 0 ? (\n            <p style={{ color: "#999", fontSize: "0.9rem" }}>\n              Aun no tienes cultivos registrados.\n            </p>\n          ) : (\n            cultivos.map(c => (\n              <div\n                key={c.id_cultivo}\n                onClick={() => seleccionarCultivo(c)}\n                style={{\n                  ...estilos.itemCultivo,\n                  borderColor: cultivoActivo?.id_cultivo === c.id_cultivo\n                    ? COLOR.cafe : COLOR.borde,\n                  background: cultivoActivo?.id_cultivo === c.id_cultivo\n                    ? "#f9f3ee" : "#fff",\n                }}\n              >\n                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "0.4rem" }}>\n                  <strong style={{ color: COLOR.cafe }}>{c.nombre_cultivo}</strong>\n                  <Badge estado={c.estado} mapa={ESTADO_CULTIVO} />\n                </div>\n                <p style={{ margin: 0, fontSize: "0.8rem", color: "#7a5c3a" }}>\n                  {c.variedad_cafe || "Variedad no especificada"} -\n                  {c.area_hectareas ? ` ${c.area_hectareas} ha` : " Area no definida"}\n                </p>\n                <p style={{ margin: "0.2rem 0 0", fontSize: "0.78rem", color: "#aaa" }}>\n                  {c.ubicacion || "Ubicacion no registrada"}\n                </p>\n              </div>\n            ))\n          )}\n        </div>\n\n        {/* Detalle de lotes del cultivo seleccionado */}\n        <div style={estilos.panelDer}>\n          {cultivoActivo ? (\n            <>\n              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>\n                <h3 style={estilos.subtitulo}>\n                  Lotes de: {cultivoActivo.nombre_cultivo}\n                </h3>\n                <Boton onClick={() => setModalLote(true)} variante="verde">\n                  + Nuevo Lote\n                </Boton>\n              </div>\n\n              {lotes.length === 0 ? (\n                <p style={{ color: "#999", fontSize: "0.9rem" }}>\n                  Este cultivo aun no tiene lotes registrados.\n                </p>\n              ) : (\n                <div style={{ display: "flex", flexDirection: "column", gap: "0.8rem" }}>\n                  {lotes.map(l => (\n                    <div key={l.id_lote} style={estilos.itemLote}>\n                      <div style={{ display: "flex", justifyContent: "space-between" }}>\n                        <strong style={{ color: COLOR.cafe }}>{l.codigo_lote}</strong>\n                        <Badge estado={l.estado_lote} mapa={ESTADO_LOTE} />\n                      </div>\n                      <div style={{ display: "flex", gap: "2rem", marginTop: "0.5rem", fontSize: "0.82rem", color: "#7a5c3a" }}>\n                        <span>\n                          Cosecha: {l.fecha_cosecha\n                            ? new Date(l.fecha_cosecha).toLocaleDateString("es-CO")\n                            : "No registrada"}\n                        </span>\n                        <span>\n                          Cantidad: {l.cantidad_kg ? `${l.cantidad_kg} kg` : "No registrada"}\n                        </span>\n                      </div>\n                      {l.codigo_qr && (\n                        <p style={{ margin: "0.4rem 0 0", fontSize: "0.75rem", color: "#aaa" }}>\n                          QR: {l.codigo_qr.substring(0, 20)}...\n                        </p>\n                      )}\n                    </div>\n                  ))}\n                </div>\n              )}\n            </>\n          ) : (\n            <div style={{ textAlign: "center", padding: "3rem", color: "#bbb" }}>\n              <p style={{ fontSize: "3rem" }}>🌿</p>\n              <p>Selecciona un cultivo para ver sus lotes</p>\n            </div>\n          )}\n        </div>\n      </div>\n\n      {/* Modal - Nuevo / Editar Cultivo */}\n      <Modal\n        abierto={modalCultivo}\n        titulo={editando ? "Editar Cultivo" : "Registrar Nuevo Cultivo"}\n        onCerrar={() => { setModalCultivo(false); setEditando(null); }}\n      >\n        <FormularioCultivo\n          inicial={editando || {}}\n          onGuardar={guardarCultivo}\n          onCancelar={() => { setModalCultivo(false); setEditando(null); }}\n        />\n      </Modal>\n\n      {/* Modal - Nuevo Lote */}\n      <Modal\n        abierto={modalLote}\n        titulo={`Registrar Lote en: ${cultivoActivo?.nombre_cultivo || ""}`}\n        onCerrar={() => setModalLote(false)}\n      >\n        <FormularioLote\n          onGuardar={guardarLote}\n          onCancelar={() => setModalLote(false)}\n        />\n      </Modal>\n    </div>\n  );\n}\n\n// ==============================================================\n// ESTILOS\n// ==============================================================\n\nconst estilos = {\n  contenedor: {\n    minHeight:  "100vh",\n    background: COLOR.gris,\n    padding:    "2rem",\n    fontFamily: "\'Segoe UI\', Roboto, sans-serif",\n    color:      COLOR.texto,\n  },\n  encabezado: {\n    display:        "flex",\n    justifyContent: "space-between",\n    alignItems:     "center",\n    marginBottom:   "1.5rem",\n  },\n  titulo: {\n    margin:     0,\n    fontSize:   "1.8rem",\n    fontWeight: 800,\n    color:      COLOR.cafe,\n  },\n  subtitulo: {\n    margin:       "0 0 1rem",\n    fontSize:     "1rem",\n    fontWeight:   700,\n    color:        COLOR.cafe,\n    borderBottom: `2px solid ${COLOR.borde}`,\n    paddingBottom: "0.5rem",\n  },\n  gridResumen: {\n    display:             "grid",\n    gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))",\n    gap:                 "1rem",\n    marginBottom:        "1.5rem",\n  },\n  gridPrincipal: {\n    display:             "grid",\n    gridTemplateColumns: "320px 1fr",\n    gap:                 "1.5rem",\n    alignItems:          "start",\n  },\n  panelIzq: {\n    background:   "#fff",\n    borderRadius: "12px",\n    border:       `1px solid ${COLOR.borde}`,\n    padding:      "1.5rem",\n  },\n  panelDer: {\n    background:   "#fff",\n    borderRadius: "12px",\n    border:       `1px solid ${COLOR.borde}`,\n    padding:      "1.5rem",\n    minHeight:    "400px",\n  },\n  itemCultivo: {\n    border:       `2px solid`,\n    borderRadius: "10px",\n    padding:      "1rem",\n    cursor:       "pointer",\n    marginBottom: "0.8rem",\n    transition:   "all 0.15s",\n  },\n  itemLote: {\n    border:       `1px solid ${COLOR.borde}`,\n    borderRadius: "10px",\n    padding:      "1rem",\n    background:   "#fafafa",\n  },\n  alerta: {\n    background:   "#fff1f0",\n    border:       "1px solid #ffccc7",\n    borderRadius: "8px",\n    padding:      "0.8rem 1rem",\n    color:        "#b91c1c",\n    marginBottom: "1rem",\n    fontSize:     "0.87rem",\n  },\n};\n'

ARCHIVOS["Backend/reportes/app/services/reportes_service.py"] = '# ==============================================================\n# modulo_07_reportes / app/services/reportes_service.py\n# Servicio principal — RF-18\n#\n# Implementa el diagrama de estados del documento oficial:\n#   Solicitado → Generando → Disponible → Descargado\n#                          ↘ Error\n#\n# Tipos de reporte soportados (RF-18: "sistema y cultivo"):\n#   general       Resumen ejecutivo de todo el sistema\n#   cultivos      Registro de fincas, lotes y producción\n#   trazabilidad  Cadena lote cosecha→secado→clasificación→venta\n#   fitosanitario Análisis IA de enfermedades y plagas\n#   ambiental     Lecturas de sensores ambientales y de suelo\n#   mercado       Precios y análisis de demanda\n#   usuarios      Usuarios del sistema y roles\n#\n# AUDITORÍA:\n#   registrar_evento_auditoria() es el punto de entrada para que\n#   cualquier módulo del sistema registre un evento de auditoría.\n#   La tabla tbl_auditoria es append-only (RNF-05).\n# ==============================================================\n\nimport json\nimport logging\nimport os\nfrom datetime import datetime, timedelta\nfrom typing import Any, Dict, List, Optional, Tuple\n\nfrom fastapi import HTTPException, status\nfrom fastapi.responses import FileResponse\nfrom sqlalchemy import text\nfrom sqlalchemy.orm import Session\n\nfrom app.core.config import settings\nfrom app.generadores.generador_pdf import generar_pdf\nfrom app.models.reportes import RegistroAuditoria, Reporte\nfrom app.schemas.reportes import (\n    AuditoriaCreate,\n    AuditoriaResponse,\n    AuditoriaFiltros,\n    ReporteListItem,\n    ReporteResponse,\n    ReporteSolicitud,\n    ResumenSistemaResponse,\n)\n\nlogger = logging.getLogger(__name__)\n\nESTADOS_LABEL = {\n    "solicitado":  "📋 Solicitado",\n    "generando":   "⏳ Generando...",\n    "disponible":  "✅ Disponible",\n    "error":       "❌ Error",\n    "descargado":  "📥 Descargado",\n}\n\n\nclass ReportesService:\n\n    def __init__(self, db: Session):\n        self.db = db\n\n    # ----------------------------------------------------------\n    # RF-18 — GENERACIÓN DE REPORTES\n    # ----------------------------------------------------------\n\n    def solicitar_reporte(\n        self,\n        solicitud:      ReporteSolicitud,\n        usuario_id:     int,\n        nombre_usuario: str = "Administrador",\n    ) -> ReporteResponse:\n        """\n        Genera un reporte siguiendo el diagrama de estados oficial:\n        solicitado → generando → disponible (o error).\n\n        La generación es síncrona para cumplir RNF-01 (< 5 s)\n        en los volúmenes de datos esperados de una finca cafetera.\n        """\n        nombre_auto = solicitud.nombre or (\n            f"Reporte {solicitud.tipo_reporte.title()} "\n            f"{datetime.utcnow().strftime(\'%d/%m/%Y %H:%M\')}"\n        )\n        params_json = json.dumps({\n            "fecha_inicio": solicitud.fecha_inicio.isoformat() if solicitud.fecha_inicio else None,\n            "fecha_fin":    solicitud.fecha_fin.isoformat()    if solicitud.fecha_fin    else None,\n        })\n\n        # ── Estado: SOLICITADO ──────────────────────────────────\n        reporte = Reporte(\n            tipo_reporte    = solicitud.tipo_reporte,\n            nombre          = nombre_auto,\n            parametros      = params_json,\n            estado          = "solicitado",\n            id_usuario      = usuario_id,\n            nombre_usuario  = nombre_usuario,\n        )\n        self.db.add(reporte)\n        self.db.commit()\n        self.db.refresh(reporte)\n\n        # ── Estado: GENERANDO ───────────────────────────────────\n        reporte.estado = "generando"\n        self.db.commit()\n\n        try:\n            datos, columnas, cabeceras, resumen = self._preparar_datos(\n                solicitud.tipo_reporte,\n                solicitud.fecha_inicio,\n                solicitud.fecha_fin,\n            )\n\n            resultado = generar_pdf(\n                tipo_reporte   = solicitud.tipo_reporte,\n                titulo         = nombre_auto,\n                datos          = datos,\n                columnas       = columnas,\n                cabeceras      = cabeceras,\n                resumen        = resumen,\n                fecha_inicio   = solicitud.fecha_inicio,\n                fecha_fin      = solicitud.fecha_fin,\n                nombre_usuario = nombre_usuario,\n            )\n\n            # ── Estado: DISPONIBLE ──────────────────────────────\n            reporte.estado         = "disponible"\n            reporte.ruta_archivo   = resultado["ruta_archivo"]\n            reporte.nombre_archivo = resultado["nombre_archivo"]\n            reporte.tamano_bytes   = resultado["tamano_bytes"]\n            reporte.num_registros  = resultado["num_registros"]\n            reporte.fecha_generado = datetime.utcnow()\n            self.db.commit()\n\n            logger.info(\n                f"Reporte \'{solicitud.tipo_reporte}\' generado: "\n                f"{resultado[\'nombre_archivo\']} "\n                f"({resultado[\'num_registros\']} registros, "\n                f"{resultado[\'tamano_bytes\']} bytes)"\n            )\n\n            # Registrar en auditoría\n            self._registrar_auditoria_interna(\n                modulo      = "reportes",\n                accion      = "generar_reporte",\n                tipo_entidad= "reporte",\n                id_entidad  = reporte.id_reporte,\n                descripcion = (\n                    f"Reporte \'{solicitud.tipo_reporte}\' generado: "\n                    f"{resultado[\'num_registros\']} registros"\n                ),\n                id_usuario  = usuario_id,\n                nombre_usuario = nombre_usuario,\n            )\n\n        except Exception as exc:\n            # ── Estado: ERROR ───────────────────────────────────\n            reporte.estado        = "error"\n            reporte.mensaje_error = str(exc)[:490]\n            self.db.commit()\n            logger.error(f"Error generando reporte {solicitud.tipo_reporte}: {exc}")\n\n        self.db.refresh(reporte)\n        return self._reporte_a_response(reporte)\n\n    def listar_reportes(self, usuario_id: int) -> List[ReporteListItem]:\n        """Lista todos los reportes generados, ordenados por fecha descendente."""\n        reportes = (\n            self.db.query(Reporte)\n            .order_by(Reporte.fecha_solicitud.desc())\n            .all()\n        )\n        return [self._reporte_a_list_item(r) for r in reportes]\n\n    def obtener_reporte(self, id_reporte: int) -> ReporteResponse:\n        """Obtiene el estado y metadata de un reporte específico."""\n        r = self._obtener_o_404(id_reporte)\n        return self._reporte_a_response(r)\n\n    def descargar_reporte(\n        self, id_reporte: int, usuario_id: int, nombre_usuario: str\n    ) -> FileResponse:\n        """\n        Retorna el archivo del reporte para descarga y transiciona\n        al estado \'descargado\' si corresponde.\n        """\n        r = self._obtener_o_404(id_reporte)\n\n        if r.estado not in ("disponible", "descargado"):\n            raise HTTPException(\n                status_code=status.HTTP_409_CONFLICT,\n                detail=(\n                    f"El reporte está en estado \'{r.estado}\' y no puede descargarse. "\n                    "Solo los reportes en estado \'disponible\' o \'descargado\' son descargables."\n                ),\n            )\n\n        if not r.ruta_archivo or not os.path.exists(r.ruta_archivo):\n            raise HTTPException(\n                status_code=status.HTTP_404_NOT_FOUND,\n                detail="El archivo del reporte no se encontró en el servidor.",\n            )\n\n        # Transición a descargado\n        if r.estado == "disponible":\n            r.estado         = "descargado"\n            r.fecha_descarga = datetime.utcnow()\n            self.db.commit()\n\n        self._registrar_auditoria_interna(\n            modulo       = "reportes",\n            accion       = "exportar",\n            tipo_entidad = "reporte",\n            id_entidad   = r.id_reporte,\n            descripcion  = f"Descarga del reporte \'{r.nombre}\'",\n            id_usuario   = usuario_id,\n            nombre_usuario = nombre_usuario,\n        )\n\n        media_type = (\n            "application/pdf"\n            if r.nombre_archivo.endswith(".pdf")\n            else "application/json"\n        )\n        return FileResponse(\n            path             = r.ruta_archivo,\n            filename         = r.nombre_archivo,\n            media_type       = media_type,\n        )\n\n    def reintentar_reporte(\n        self, id_reporte: int, usuario_id: int, nombre_usuario: str\n    ) -> ReporteResponse:\n        """\n        Reintento de un reporte en estado \'error\'.\n        Diagrama de estados: error → solicitado (→ generando → disponible).\n        """\n        r = self._obtener_o_404(id_reporte)\n        if r.estado != "error":\n            raise HTTPException(\n                status_code=status.HTTP_409_CONFLICT,\n                detail=f"Solo reportes en estado \'error\' pueden reintentarse. Estado actual: \'{r.estado}\'.",\n            )\n\n        parametros = json.loads(r.parametros) if r.parametros else {}\n        solicitud  = ReporteSolicitud(\n            tipo_reporte = r.tipo_reporte,\n            nombre       = r.nombre,\n            fecha_inicio = parametros.get("fecha_inicio"),\n            fecha_fin    = parametros.get("fecha_fin"),\n        )\n        # Reintentar crea un nuevo registro (trazabilidad limpia)\n        return self.solicitar_reporte(solicitud, usuario_id, nombre_usuario)\n\n    # ----------------------------------------------------------\n    # RF-18 — AUDITORÍA\n    # ----------------------------------------------------------\n\n    def registrar_evento_auditoria(self, evento: AuditoriaCreate) -> int:\n        """\n        Registra un evento de auditoría (append-only, RNF-05).\n        Retorna el id del registro creado.\n        """\n        registro = RegistroAuditoria(\n            modulo         = evento.modulo,\n            accion         = evento.accion,\n            tipo_entidad   = evento.tipo_entidad,\n            id_entidad     = evento.id_entidad,\n            descripcion    = evento.descripcion,\n            resultado      = evento.resultado,\n            id_usuario     = evento.id_usuario,\n            nombre_usuario = evento.nombre_usuario,\n            rol_usuario    = evento.rol_usuario,\n            ip_origen      = evento.ip_origen,\n            dato_anterior  = evento.dato_anterior,\n            dato_nuevo     = evento.dato_nuevo,\n        )\n        self.db.add(registro)\n        self.db.commit()\n        self.db.refresh(registro)\n        return registro.id_auditoria\n\n    def consultar_auditoria(\n        self, filtros: AuditoriaFiltros\n    ) -> Tuple[List[AuditoriaResponse], int]:\n        """\n        Consulta paginada del log de auditoría con filtros.\n        Retorna (registros, total).\n        """\n        q = self.db.query(RegistroAuditoria)\n\n        if filtros.modulo:\n            q = q.filter(RegistroAuditoria.modulo == filtros.modulo)\n        if filtros.accion:\n            q = q.filter(RegistroAuditoria.accion == filtros.accion)\n        if filtros.resultado:\n            q = q.filter(RegistroAuditoria.resultado == filtros.resultado)\n        if filtros.id_usuario:\n            q = q.filter(RegistroAuditoria.id_usuario == filtros.id_usuario)\n        if filtros.fecha_desde:\n            q = q.filter(RegistroAuditoria.fecha_evento >= filtros.fecha_desde)\n        if filtros.fecha_hasta:\n            q = q.filter(RegistroAuditoria.fecha_evento <= filtros.fecha_hasta)\n\n        total   = q.count()\n        offset  = (filtros.page - 1) * filtros.page_size\n        registros = (\n            q.order_by(RegistroAuditoria.fecha_evento.desc())\n            .offset(offset)\n            .limit(filtros.page_size)\n            .all()\n        )\n\n        return [\n            AuditoriaResponse(\n                id_auditoria   = r.id_auditoria,\n                modulo         = r.modulo,\n                accion         = r.accion,\n                tipo_entidad   = r.tipo_entidad,\n                id_entidad     = r.id_entidad,\n                descripcion    = r.descripcion,\n                resultado      = r.resultado,\n                id_usuario     = r.id_usuario,\n                nombre_usuario = r.nombre_usuario,\n                rol_usuario    = r.rol_usuario,\n                ip_origen      = r.ip_origen,\n                dato_anterior  = r.dato_anterior,\n                dato_nuevo     = r.dato_nuevo,\n                fecha_evento   = r.fecha_evento,\n            )\n            for r in registros\n        ], total\n\n    # ----------------------------------------------------------\n    # RESUMEN GLOBAL DEL SISTEMA\n    # ----------------------------------------------------------\n\n    def resumen_sistema(self) -> ResumenSistemaResponse:\n        """\n        Métricas globales del sistema para el panel del Administrador.\n        Consulta todas las tablas del sistema via SQL directo.\n        Si alguna tabla no existe (módulo no desplegado), retorna 0.\n        """\n        ahora      = datetime.utcnow()\n        hace_7dias = ahora - timedelta(days=7)\n        hoy_inicio = ahora.replace(hour=0, minute=0, second=0, microsecond=0)\n\n        def _count(sql: str, params: dict = None) -> int:\n            try:\n                r = self.db.execute(text(sql), params or {}).fetchone()\n                return int(r[0]) if r and r[0] else 0\n            except Exception:\n                return 0\n\n        return ResumenSistemaResponse(\n            total_usuarios      = _count("SELECT COUNT(*) FROM tbl_usuario"),\n            usuarios_activos    = _count(\n                "SELECT COUNT(*) FROM tbl_usuario WHERE estado_cuenta=\'activo\'"\n            ),\n            total_cultivos      = _count("SELECT COUNT(*) FROM tbl_cultivo"),\n            total_lotes         = _count("SELECT COUNT(*) FROM tbl_lote"),\n            total_analisis_ia   = _count("SELECT COUNT(*) FROM tbl_analisis_imagen"  # BUG-009 FIX),\n            analisis_ultima_semana = _count(\n                "SELECT COUNT(*) FROM tbl_analisis_imagen WHERE fecha_analisis >= :f",\n                {"f": hace_7dias},\n            ),\n            lotes_en_proceso    = _count(\n                "SELECT COUNT(*) FROM tbl_trazabilidad_lote "\n                "WHERE estado IN (\'registrado\',\'disponible\',\'en_analisis\')"\n            ),\n            lotes_vendidos      = _count(\n                "SELECT COUNT(*) FROM tbl_trazabilidad_lote WHERE estado=\'vendido\'"\n            ),\n            total_analisis_precio  = _count("SELECT COUNT(*) FROM tbl_analisis_precio"),\n            total_analisis_demanda = _count("SELECT COUNT(*) FROM tbl_analisis_demanda"),\n            eventos_auditoria_hoy  = _count(\n                "SELECT COUNT(*) FROM tbl_auditoria WHERE fecha_evento >= :f",\n                {"f": hoy_inicio},\n            ),\n            errores_sistema_semana = _count(\n                "SELECT COUNT(*) FROM tbl_auditoria "\n                "WHERE resultado=\'fallido\' AND fecha_evento >= :f",\n                {"f": hace_7dias},\n            ),\n            reportes_generados  = _count(\n                "SELECT COUNT(*) FROM tbl_reporte WHERE estado IN (\'disponible\',\'descargado\')"\n            ),\n            fecha_actualizacion = ahora,\n        )\n\n    # ----------------------------------------------------------\n    # PREPARACIÓN DE DATOS POR TIPO\n    # ----------------------------------------------------------\n\n    def _preparar_datos(\n        self,\n        tipo_reporte:  str,\n        fecha_inicio:  Optional[datetime],\n        fecha_fin:     Optional[datetime],\n    ) -> Tuple[List[Dict], List[str], List[str], Dict]:\n        """\n        Despacha al preparador correcto según el tipo de reporte.\n        Retorna (datos, columnas, cabeceras, resumen).\n        """\n        metodos = {\n            "general":       self._datos_general,\n            "cultivos":      self._datos_cultivos,\n            "trazabilidad":  self._datos_trazabilidad,\n            "fitosanitario": self._datos_fitosanitario,\n            "ambiental":     self._datos_ambiental,\n            "mercado":       self._datos_mercado,\n            "usuarios":      self._datos_usuarios,\n        }\n        return metodos[tipo_reporte](fecha_inicio, fecha_fin)\n\n    def _q(self, sql: str, params: dict = None) -> List[Any]:\n        """Ejecuta SQL y retorna lista de Row. Silencia errores de tabla inexistente."""\n        try:\n            return self.db.execute(text(sql), params or {}).fetchall()\n        except Exception as e:\n            logger.warning(f"Consulta no disponible: {e}")\n            return []\n\n    def _datos_general(self, fi, ff):\n        resumen = self.resumen_sistema()\n        datos   = [\n            {"indicador": "Total usuarios",          "valor": resumen.total_usuarios},\n            {"indicador": "Usuarios activos",         "valor": resumen.usuarios_activos},\n            {"indicador": "Total cultivos",           "valor": resumen.total_cultivos},\n            {"indicador": "Total lotes",              "valor": resumen.total_lotes},\n            {"indicador": "Análisis IA realizados",   "valor": resumen.total_analisis_ia},\n            {"indicador": "Lotes en proceso",         "valor": resumen.lotes_en_proceso},\n            {"indicador": "Lotes vendidos",           "valor": resumen.lotes_vendidos},\n            {"indicador": "Eventos auditoría hoy",    "valor": resumen.eventos_auditoria_hoy},\n            {"indicador": "Reportes generados",       "valor": resumen.reportes_generados},\n        ]\n        return datos, ["indicador", "valor"], ["Indicador", "Valor"], {\n            "Fecha generación": datetime.utcnow().strftime("%d/%m/%Y %H:%M"),\n            "Sistema":          settings.NOMBRE_ORGANIZACION,\n        }\n\n    def _datos_cultivos(self, fi, ff):\n        filas = self._q("""\n            SELECT c.id_cultivo, c.nombre_cultivo, c.ubicacion,\n                   c.fecha_siembra, c.variedad_cafe,  -- BUG-009 FIX\n                   u.nombre, u.apellido,\n                   COUNT(l.id_lote) AS num_lotes\n            FROM   tbl_cultivo c\n            LEFT JOIN tbl_usuario u ON c.id_usuario = u.id_usuario\n            LEFT JOIN tbl_lote    l ON l.id_cultivo = c.id_cultivo\n            GROUP BY c.id_cultivo\n            ORDER BY c.fecha_siembra DESC\n        """)\n        datos = [dict(zip(\n            ["id","nombre_cultivo","ubicacion","fecha_siembra","variedad",\n             "productor_nombre","productor_apellido","num_lotes"], r\n        )) for r in filas]\n        resumen = {\n            "Total cultivos": len(datos),\n            "Total lotes":    sum(d.get("num_lotes", 0) for d in datos),\n        }\n        cabs = ["ID","Cultivo","Ubicación","Fecha siembra","Variedad","Productor","Apellido","Lotes"]\n        cols = ["id","nombre_cultivo","ubicacion","fecha_siembra","variedad",\n                "productor_nombre","productor_apellido","num_lotes"]\n        return datos, cols, cabs, resumen\n\n    def _datos_trazabilidad(self, fi, ff):\n        params = {}\n        filtro_fecha = ""\n        if fi:\n            filtro_fecha += " AND t.fecha_creacion >= :fi"\n            params["fi"] = fi\n        if ff:\n            filtro_fecha += " AND t.fecha_creacion <= :ff"\n            params["ff"] = ff\n\n        filas = self._q(f"""\n            SELECT t.codigo_lote, t.variedad_cafe, t.estado,\n                   t.kg_pergamino_seco, t.clasificacion_calidad,\n                   t.comprador, t.precio_venta_kg,\n                   t.fecha_creacion, t.fecha_venta\n            FROM   tbl_trazabilidad_lote t\n            WHERE  1=1 {filtro_fecha}\n            ORDER BY t.fecha_creacion DESC\n        """, params)\n        datos = [dict(zip(\n            ["codigo_lote","variedad","estado","kg","clasificacion",\n             "comprador","precio_venta","fecha_registro","fecha_venta"], r\n        )) for r in filas]\n        vendidos = [d for d in datos if d.get("estado") == "vendido"]\n        kg_total = sum(float(d.get("kg") or 0) for d in datos)\n        resumen  = {\n            "Total lotes":    len(datos),\n            "Lotes vendidos": len(vendidos),\n            "Kg totales":     f"{kg_total:,.0f}",\n        }\n        cabs = ["Código","Variedad","Estado","Kg","Calidad","Comprador","Precio/kg","Registro","Venta"]\n        cols = ["codigo_lote","variedad","estado","kg","clasificacion",\n                "comprador","precio_venta","fecha_registro","fecha_venta"]\n        return datos, cols, cabs, resumen\n\n    def _datos_fitosanitario(self, fi, ff):\n        params = {}\n        filtro = ""\n        if fi:\n            filtro += " AND a.fecha_analisis >= :fi"; params["fi"] = fi\n        if ff:\n            filtro += " AND a.fecha_analisis <= :ff"; params["ff"] = ff\n\n        filas = self._q(f"""\n            SELECT a.id_analisis, a.resultado, a.recomendacion,\n                   a.fecha_analisis, c.nombre_cultivo, c.ubicacion\n            FROM   tbl_analisis_imagen a  -- BUG-009 FIX\n            JOIN   tbl_cultivo         c ON a.id_cultivo = c.id_cultivo\n            WHERE  1=1 {filtro}\n            ORDER BY a.fecha_analisis DESC\n        """, params)\n        datos = [dict(zip(\n            ["id","resultado","recomendacion","fecha","cultivo","ubicacion"], r\n        )) for r in filas]\n        resumen = {\n            "Total análisis": len(datos),\n            "Período": f"{fi.strftime(\'%d/%m/%Y\') if fi else \'Todo\'} - {ff.strftime(\'%d/%m/%Y\') if ff else \'Hoy\'}",\n        }\n        cabs = ["ID","Diagnóstico","Recomendación","Fecha","Cultivo","Ubicación"]\n        cols = ["id","resultado","recomendacion","fecha","cultivo","ubicacion"]\n        return datos, cols, cabs, resumen\n\n    def _datos_ambiental(self, fi, ff):\n        params = {}\n        filtro = ""\n        if fi:\n            filtro += " AND s.fecha_lectura >= :fi"; params["fi"] = fi\n        if ff:\n            filtro += " AND s.fecha_lectura <= :ff"; params["ff"] = ff\n\n        filas = self._q(f"""\n            -- BUG-009 FIX: tbl_lectura_sensor no existe\n            SELECT \'ambiental\' AS tipo_sensor,\n                   CONCAT(\'T:\', a.temperatura, \' H:\', a.humedad_relativa) AS valor,\n                   \'varios\' AS unidad,\n                   a.fecha_registro AS fecha_lectura,\n                   CASE WHEN a.temperatura > 35 OR a.humedad_relativa > 95 THEN 1 ELSE 0 END AS alerta_activa,\n                   c.nombre_cultivo\n            FROM   tbl_monitoreo_ambiental a\n            JOIN   tbl_cultivo             c ON a.id_cultivo = c.id_cultivo\n            WHERE  1=1 {filtro}\n            ORDER BY a.fecha_registro DESC\n            LIMIT 500\n        """, params)\n        datos = [dict(zip(\n            ["tipo","valor","unidad","fecha","alerta","cultivo"], r\n        )) for r in filas]\n        alertas = [d for d in datos if d.get("alerta")]\n        resumen = {\n            "Total lecturas": len(datos),\n            "Alertas activas": len(alertas),\n        }\n        cabs = ["Sensor","Valor","Unidad","Fecha","Alerta","Cultivo"]\n        cols = ["tipo","valor","unidad","fecha","alerta","cultivo"]\n        return datos, cols, cabs, resumen\n\n    def _datos_mercado(self, fi, ff):\n        filas = self._q("""\n            SELECT ap.tendencia, ap.precio_promedio, ap.precio_minimo,\n                   ap.precio_maximo, ap.variacion_pct,\n                   ap.precio_proyectado, ap.alerta_activa,\n                   ap.fecha_analisis\n            FROM   tbl_analisis_precio ap\n            ORDER BY ap.fecha_analisis DESC\n            LIMIT 100\n        """)\n        datos = [dict(zip(\n            ["tendencia","prom","min","max","variacion",\n             "proyectado","alerta","fecha"], r\n        )) for r in filas]\n        resumen = {"Total análisis de precio": len(datos)}\n        cabs = ["Tendencia","Promedio","Mínimo","Máximo","Var%","Proyectado","Alerta","Fecha"]\n        cols = ["tendencia","prom","min","max","variacion","proyectado","alerta","fecha"]\n        return datos, cols, cabs, resumen\n\n    def _datos_usuarios(self, fi, ff):\n        filas = self._q("""\n            SELECT u.id_usuario, u.nombre, u.apellido, u.correo,\n                   r.nombre_rol, u.estado_cuenta, u.fecha_registro\n            FROM   tbl_usuario u\n            JOIN   tbl_rol     r ON u.id_rol = r.id_rol\n            ORDER BY u.fecha_registro DESC\n        """)\n        datos = [dict(zip(\n            ["id","nombre","apellido","correo","rol","estado","fecha_registro"], r\n        )) for r in filas]\n        activos = [d for d in datos if d.get("estado") == "activo"]\n        resumen = {\n            "Total usuarios": len(datos),\n            "Activos":        len(activos),\n            "Inactivos":      len(datos) - len(activos),\n        }\n        cabs = ["ID","Nombre","Apellido","Correo","Rol","Estado","Registro"]\n        cols = ["id","nombre","apellido","correo","rol","estado","fecha_registro"]\n        return datos, cols, cabs, resumen\n\n    # ----------------------------------------------------------\n    # HELPERS PRIVADOS\n    # ----------------------------------------------------------\n\n    def _obtener_o_404(self, id_reporte: int) -> Reporte:\n        r = self.db.query(Reporte).filter(Reporte.id_reporte == id_reporte).first()\n        if not r:\n            raise HTTPException(\n                status_code=status.HTTP_404_NOT_FOUND,\n                detail=f"Reporte ID {id_reporte} no encontrado.",\n            )\n        return r\n\n    def _registrar_auditoria_interna(self, **kwargs):\n        """Registra un evento de auditoría sin lanzar excepción si falla."""\n        try:\n            self.registrar_evento_auditoria(AuditoriaCreate(**kwargs))\n        except Exception as e:\n            logger.warning(f"No se pudo registrar auditoría: {e}")\n\n    def _reporte_a_response(self, r: Reporte) -> ReporteResponse:\n        return ReporteResponse(\n            id_reporte     = r.id_reporte,\n            tipo_reporte   = r.tipo_reporte,\n            nombre         = r.nombre,\n            estado         = r.estado,\n            estado_label   = ESTADOS_LABEL.get(r.estado, r.estado),\n            ruta_archivo   = r.ruta_archivo,\n            nombre_archivo = r.nombre_archivo,\n            tamano_kb      = round(r.tamano_bytes / 1024, 1) if r.tamano_bytes else None,\n            num_registros  = r.num_registros,\n            mensaje_error  = r.mensaje_error,\n            nombre_usuario = r.nombre_usuario,\n            fecha_solicitud = r.fecha_solicitud,\n            fecha_generado  = r.fecha_generado,\n            fecha_descarga  = r.fecha_descarga,\n        )\n\n    def _reporte_a_list_item(self, r: Reporte) -> ReporteListItem:\n        return ReporteListItem(\n            id_reporte     = r.id_reporte,\n            tipo_reporte   = r.tipo_reporte,\n            nombre         = r.nombre,\n            estado         = r.estado,\n            estado_label   = ESTADOS_LABEL.get(r.estado, r.estado),\n            tamano_kb      = round(r.tamano_bytes / 1024, 1) if r.tamano_bytes else None,\n            num_registros  = r.num_registros,\n            nombre_usuario = r.nombre_usuario,\n            fecha_solicitud = r.fecha_solicitud,\n            fecha_generado  = r.fecha_generado,\n        )\n'

ARCHIVOS["Backend/granovital_login/granovital/app/models/usuario.py"] = '# =============================================================\n# app/models/usuario.py\n# Modelos ORM SQLAlchemy — tbl_usuario, tbl_rol, tbl_permiso\n# Trazabilidad: RF-01, RF-16, RF-17 | RN-01 | RNF-04\n# =============================================================\n\nfrom datetime import datetime\nfrom sqlalchemy import (\n    Column, Integer, String, DateTime, Enum,\n    ForeignKey, Text, UniqueConstraint\n)\nfrom sqlalchemy.orm import relationship\nfrom app.core.database import Base\n\n\nclass Rol(Base):\n    """\n    tbl_rol — Define los roles del sistema.\n    Roles: Administrador, Caficultor, Productor, Comercializador, Consumidor\n    Soporta RN-01 (acceso por rol) y RF-17 (asignación de roles).\n    """\n    __tablename__ = "tbl_rol"\n\n    id_rol        = Column(Integer, primary_key=True, autoincrement=True)\n    nombre_rol    = Column(String(50), nullable=False, unique=True)\n    descripcion   = Column(String(150), nullable=True)\n    fecha_creacion = Column(DateTime, nullable=False, default=datetime.utcnow)\n\n    # Relaciones\n    usuarios   = relationship("Usuario", back_populates="rol")\n    permisos   = relationship("RolPermiso", back_populates="rol")\n\n    def __repr__(self) -> str:\n        return f"<Rol id={self.id_rol} nombre=\'{self.nombre_rol}\'>"\n\n\nclass Permiso(Base):\n    """\n    tbl_permiso — Catálogo de permisos atómicos del sistema.\n    Permite control granular de acceso por módulo (RF-17).\n    """\n    __tablename__ = "tbl_permiso"\n\n    id_permiso     = Column(Integer, primary_key=True, autoincrement=True)\n    nombre_permiso = Column(String(100), nullable=False, unique=True)\n    descripcion    = Column(String(200), nullable=True)\n    modulo         = Column(String(80), nullable=True)\n\n    # Relaciones\n    roles = relationship("RolPermiso", back_populates="permiso")\n\n    def __repr__(self) -> str:\n        return f"<Permiso \'{self.nombre_permiso}\'>"\n\n\nclass RolPermiso(Base):\n    """\n    tbl_rol_permiso — Tabla puente rol-permiso.\n    Implementa RN-01: el sistema solo permite acceso según el rol asignado.\n    """\n    __tablename__ = "tbl_rol_permiso"\n\n    id_rol_permiso = Column(Integer, primary_key=True, autoincrement=True)\n    id_rol         = Column(Integer, ForeignKey("tbl_rol.id_rol", ondelete="CASCADE"), nullable=False)\n    id_permiso     = Column(Integer, ForeignKey("tbl_permiso.id_permiso", ondelete="CASCADE"), nullable=False)\n\n    __table_args__ = (\n        UniqueConstraint("id_rol", "id_permiso", name="uq_rol_permiso"),\n    )\n\n    # Relaciones\n    rol     = relationship("Rol", back_populates="permisos")\n    permiso = relationship("Permiso", back_populates="roles")\n\n\nclass Usuario(Base):\n    """\n    tbl_usuario — Usuarios del sistema GranoVital IA.\n    La contraseña se almacena como hash bcrypt (RNF-04).\n    El estado_cuenta controla si el usuario puede autenticarse (RF-01).\n    """\n    __tablename__ = "tbl_usuario"\n\n    id_usuario     = Column(Integer, primary_key=True, autoincrement=True)\n    nombre         = Column(String(100), nullable=False)\n    apellido       = Column(String(100), nullable=False)\n    correo         = Column(String(150), nullable=False, unique=True)\n    contrasena     = Column(String(255), nullable=False, comment="Hash bcrypt — nunca texto plano")\n    telefono       = Column(String(20), nullable=True)\n    fecha_registro = Column(DateTime, nullable=False, default=datetime.utcnow)\n    estado_cuenta  = Column(\n        Enum("activo", "inactivo", "suspendido"),\n        nullable=False,\n        default="activo"\n    )\n    intentos_fallidos = Column(Integer, nullable=False, default=0,\n                               comment="Contador de intentos de login fallidos")\n    ultimo_acceso     = Column(DateTime, nullable=True,\n                               comment="Fecha del último login exitoso")\n    # BUG-015 FIX: timestamp para liberar bloqueo automático\n    fecha_suspension  = Column(DateTime, nullable=True,\n                               comment="Momento de suspensión — se libera tras LOGIN_LOCKOUT_MINUTES")\n    id_rol         = Column(Integer, ForeignKey("tbl_rol.id_rol"), nullable=False)\n\n    # Relaciones\n    rol = relationship("Rol", back_populates="usuarios")\n\n    @property\n    def nombre_completo(self) -> str:\n        return f"{self.nombre} {self.apellido}"\n\n    @property\n    def esta_activo(self) -> bool:\n        return bool(self.estado_cuenta == "activo")\n\n    def __repr__(self) -> str:\n        return f"<Usuario id={self.id_usuario} correo=\'{self.correo}\' rol=\'{self.rol.nombre_rol if self.rol else None}\'>"\n'

ARCHIVOS["Backend/reportes/app/generadores/generador_pdf.py"] = '# ==============================================================\n# modulo_07_reportes / app/generadores/generador_pdf.py\n#\n# Generador de reportes en formato PDF usando reportlab.\n# El Diagrama de Actividad del documento oficial especifica:\n#   Usuario: seleccionar tipo → elegir tipo → confirmar\n#   Sistema: consultar BD → generar PDF → mostrar descarga\n#\n# DECISIÓN TÉCNICA:\n#   Se usa reportlab (Pure Python, sin dependencias del SO)\n#   porque es la biblioteca estándar de facto para generación\n#   programática de PDFs en Python. Es adecuada para entornos\n#   rurales con infraestructura limitada.\n#   Si reportlab no está disponible, el módulo genera un JSON\n#   estructurado como fallback (modo degradado).\n#\n# RF-18: "reportes estadísticos en PDF o Excel" (del Test Plan\n#         CP-08, que menciona ambos formatos).\n# ==============================================================\n\nimport json\nimport os\nfrom datetime import datetime\nfrom typing import Any, Dict, List, Optional\n\nfrom app.core.config import settings\n\n# Intentar importar reportlab (modo completo vs degradado)\ntry:\n    from reportlab.lib import colors\n    from reportlab.lib.pagesizes import A4\n    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle\n    from reportlab.lib.units import cm\n    from reportlab.platypus import (\n        Paragraph, SimpleDocTemplate, Spacer, Table, TableStyle,\n    )\n    REPORTLAB_OK = True\nexcept ImportError:\n    REPORTLAB_OK = False\n\n\n# Paleta de colores GranoVital\nCOLOR_CAFE    = (0.435, 0.227, 0.106)   # #6f3a1b\nCOLOR_VERDE   = (0.176, 0.478, 0.227)   # #2d7a3a\nCOLOR_HEADER  = (0.412, 0.322, 0.235)   # encabezados de tabla\n\n\ndef _asegurar_directorio():\n    os.makedirs(settings.REPORTES_DIR, exist_ok=True)\n\n\ndef _nombre_archivo(tipo_reporte: str) -> str:\n    ts = datetime.utcnow().strftime("%Y%m%d_%H%M%S")\n    return f"granovital_{tipo_reporte}_{ts}.pdf"\n\n\ndef _color_rl(rgb_tuple):\n    """Convierte tupla (r,g,b) en 0-1 a color reportlab."""\n    from reportlab.lib.colors import Color\n    return Color(*rgb_tuple)\n\n\ndef generar_pdf(\n    tipo_reporte:  str,\n    titulo:        str,\n    datos:         List[Dict[str, Any]],\n    columnas:      List[str],\n    cabeceras:     List[str],\n    resumen:       Optional[Dict[str, Any]] = None,\n    fecha_inicio:  Optional[datetime] = None,\n    fecha_fin:     Optional[datetime] = None,\n    nombre_usuario: str = "Administrador",\n) -> Dict[str, Any]:\n    """\n    Genera un PDF del reporte y lo guarda en REPORTES_DIR.\n\n    Retorna:\n      {\n        "ruta_archivo":   str,\n        "nombre_archivo": str,\n        "tamano_bytes":   int,\n        "num_registros":  int,\n      }\n\n    Si reportlab no está disponible, genera un JSON de respaldo\n    y retorna la ruta a ese archivo.\n    """\n    _asegurar_directorio()\n    nombre_arch = _nombre_archivo(tipo_reporte)\n    ruta_completa = os.path.join(settings.REPORTES_DIR, nombre_arch)\n\n    if REPORTLAB_OK:\n        return _generar_con_reportlab(\n            ruta_completa, nombre_arch, titulo, tipo_reporte,\n            datos, columnas, cabeceras, resumen,\n            fecha_inicio, fecha_fin, nombre_usuario,\n        )\n    else:\n        return _generar_json_fallback(\n            ruta_completa, nombre_arch, tipo_reporte,\n            datos, resumen, fecha_inicio, fecha_fin,\n        )\n\n\ndef _generar_con_reportlab(\n    ruta, nombre_arch, titulo, tipo_reporte,\n    datos, columnas, cabeceras, resumen,\n    fecha_inicio, fecha_fin, nombre_usuario,\n) -> Dict[str, Any]:\n\n    doc    = SimpleDocTemplate(\n        ruta, pagesize=A4,\n        topMargin=2*cm, bottomMargin=2*cm,\n        leftMargin=2*cm, rightMargin=2*cm,\n    )\n    estilos = getSampleStyleSheet()\n    historia = []\n\n    c_cafe  = _color_rl(COLOR_CAFE)\n    c_verde = _color_rl(COLOR_VERDE)\n\n    # ── Encabezado ────────────────────────────────────────────\n    estilo_titulo = ParagraphStyle(\n        "Titulo",\n        parent=estilos["Title"],\n        fontSize=18,\n        textColor=c_cafe,\n        spaceAfter=4,\n    )\n    estilo_sub = ParagraphStyle(\n        "Sub",\n        parent=estilos["Normal"],\n        fontSize=10,\n        textColor=colors.HexColor("#7a5c3a"),\n        spaceAfter=2,\n    )\n    estilo_normal = ParagraphStyle(\n        "Normal2",\n        parent=estilos["Normal"],\n        fontSize=9,\n        spaceAfter=3,\n    )\n\n    historia.append(Paragraph(settings.NOMBRE_ORGANIZACION, estilo_sub))\n    historia.append(Paragraph(titulo, estilo_titulo))\n\n    # Período y metadata\n    periodo_texto = ""\n    if fecha_inicio and fecha_fin:\n        periodo_texto = (\n            f"Período: {fecha_inicio.strftime(\'%d/%m/%Y\')} "\n            f"— {fecha_fin.strftime(\'%d/%m/%Y\')}"\n        )\n    elif fecha_inicio:\n        periodo_texto = f"Desde: {fecha_inicio.strftime(\'%d/%m/%Y\')}"\n\n    historia.append(Paragraph(\n        f"Generado por: {nombre_usuario} "\n        f"| Fecha: {datetime.utcnow().strftime(\'%d/%m/%Y %H:%M\')} UTC",\n        estilo_sub,\n    ))\n    if periodo_texto:\n        historia.append(Paragraph(periodo_texto, estilo_sub))\n    historia.append(Spacer(1, 0.4*cm))\n\n    # ── Sección de resumen ────────────────────────────────────\n    if resumen:\n        historia.append(Paragraph("Resumen ejecutivo", ParagraphStyle(\n            "H2", parent=estilos["Heading2"], fontSize=12,\n            textColor=c_cafe, spaceBefore=8,\n        )))\n        resumen_data = [["Indicador", "Valor"]]\n        for k, v in resumen.items():\n            resumen_data.append([str(k), str(v)])\n\n        tabla_res = Table(resumen_data, colWidths=[9*cm, 7*cm])\n        tabla_res.setStyle(TableStyle([\n            ("BACKGROUND", (0, 0), (-1, 0), c_cafe),\n            ("TEXTCOLOR",  (0, 0), (-1, 0), colors.white),\n            ("FONTNAME",   (0, 0), (-1, 0), "Helvetica-Bold"),\n            ("FONTSIZE",   (0, 0), (-1, 0), 10),\n            ("ROWBACKGROUNDS", (0, 1), (-1, -1), [colors.white, colors.HexColor("#f9f3ee")]),\n            ("FONTSIZE",   (0, 1), (-1, -1), 9),\n            ("GRID",       (0, 0), (-1, -1), 0.5, colors.HexColor("#d4b896")),\n            ("VALIGN",     (0, 0), (-1, -1), "MIDDLE"),\n            ("TOPPADDING", (0, 0), (-1, -1), 5),\n            ("BOTTOMPADDING", (0, 0), (-1, -1), 5),\n        ]))\n        historia.append(tabla_res)\n        historia.append(Spacer(1, 0.5*cm))\n\n    # ── Tabla de datos ─────────────────────────────────────────\n    if datos and cabeceras:\n        historia.append(Paragraph(\n            f"Detalle ({len(datos)} registro(s))",\n            ParagraphStyle("H2", parent=estilos["Heading2"],\n                           fontSize=12, textColor=c_cafe, spaceBefore=8),\n        ))\n\n        tabla_datos = [cabeceras]\n        for fila in datos:\n            row = []\n            # BUG-017 FIX: garantizar dict aunque SQLAlchemy retorne Row\n            if not isinstance(fila, dict):\n                fila = dict(fila._mapping)\n            for col in columnas:\n                val = fila.get(col, "")\n                if isinstance(val, datetime):\n                    val = val.strftime("%d/%m/%Y %H:%M")\n                elif val is None:\n                    val = "—"\n                row.append(str(val)[:80])  # truncar celdas muy largas\n            tabla_datos.append(row)\n\n        # Ancho dinámico de columnas\n        n_cols    = len(cabeceras)\n        ancho_disp = 17 * cm\n        col_w     = [ancho_disp / n_cols] * n_cols\n\n        tabla = Table(tabla_datos, colWidths=col_w, repeatRows=1)\n        tabla.setStyle(TableStyle([\n            ("BACKGROUND",  (0, 0), (-1, 0), c_cafe),\n            ("TEXTCOLOR",   (0, 0), (-1, 0), colors.white),\n            ("FONTNAME",    (0, 0), (-1, 0), "Helvetica-Bold"),\n            ("FONTSIZE",    (0, 0), (-1, 0), 8),\n            ("ROWBACKGROUNDS", (0, 1), (-1, -1),\n             [colors.white, colors.HexColor("#f9f3ee")]),\n            ("FONTSIZE",    (0, 1), (-1, -1), 7.5),\n            ("GRID",        (0, 0), (-1, -1), 0.4, colors.HexColor("#d4b896")),\n            ("VALIGN",      (0, 0), (-1, -1), "MIDDLE"),\n            ("TOPPADDING",  (0, 0), (-1, -1), 4),\n            ("BOTTOMPADDING", (0, 0), (-1, -1), 4),\n            ("WORDWRAP",    (0, 0), (-1, -1), True),\n        ]))\n        historia.append(tabla)\n\n    # ── Pie de página ─────────────────────────────────────────\n    historia.append(Spacer(1, 1*cm))\n    historia.append(Paragraph(\n        f"— {settings.NOMBRE_ORGANIZACION} · Reporte generado automáticamente —",\n        ParagraphStyle("Pie", parent=estilos["Normal"],\n                       fontSize=7, textColor=colors.grey, alignment=1),\n    ))\n\n    doc.build(historia)\n\n    tamano = os.path.getsize(ruta)\n    return {\n        "ruta_archivo":   ruta,\n        "nombre_archivo": nombre_arch,\n        "tamano_bytes":   tamano,\n        "num_registros":  len(datos),\n    }\n\n\ndef _generar_json_fallback(\n    ruta, nombre_arch, tipo_reporte, datos, resumen, fecha_inicio, fecha_fin,\n) -> Dict[str, Any]:\n    """\n    Modo degradado: cuando reportlab no está disponible genera JSON.\n    El nombre de archivo cambia a .json para que el cliente lo detecte.\n    """\n    nombre_json = nombre_arch.replace(".pdf", ".json")\n    ruta_json   = ruta.replace(".pdf", ".json")\n\n    payload = {\n        "tipo_reporte": tipo_reporte,\n        "generado_en":  datetime.utcnow().isoformat(),\n        "resumen":      resumen or {},\n        "registros":    len(datos),\n        "datos":        datos,\n        "nota": (\n            "Reporte generado en formato JSON porque reportlab "\n            "no está instalado. Instale con: pip install reportlab"\n        ),\n    }\n    with open(ruta_json, "w", encoding="utf-8") as f:\n        json.dump(payload, f, ensure_ascii=False, indent=2, default=str)\n\n    tamano = os.path.getsize(ruta_json)\n    return {\n        "ruta_archivo":   ruta_json,\n        "nombre_archivo": nombre_json,\n        "tamano_bytes":   tamano,\n        "num_registros":  len(datos),\n    }\n'

ARCHIVOS["Backend/cultivos/app/services/cultivo_service.py"] = '# ==============================================================\n# modulo_02_cultivos / app/services/cultivo_service.py\n# Logica de negocio - Cultivos, Lotes y Sensores\n#\n# Reglas implementadas:\n#   RN-02  Todo lote debe tener trazabilidad completa antes\n#          de pasar al estado \'vendido\'\n#   RNF-05 Integridad - eliminacion logica (no fisica)\n#   RNF-06 Soporte para nuevos sensores IoT sin cambios de schema\n#\n# Casos de prueba cubiertos:\n#   CP-03  Registro cultivo\n#   CP-04  Registro lote\n# ==============================================================\n\nimport secrets\nimport logging\nfrom typing import List, Optional\n\nfrom fastapi import HTTPException, status\nfrom sqlalchemy import func, text\nfrom sqlalchemy.orm import Session\n\nfrom app.models.cultivo import Cultivo, Lote, Sensor\nfrom app.schemas.cultivo import (\n    CultivoCreate, CultivoUpdate,\n    LoteCreate, LoteUpdate,\n    SensorCreate,\n    ResumenCultivoResponse,\n)\n\nlogger = logging.getLogger(__name__)\n\n\n# ==============================================================\n# TRANSICIONES VALIDAS DE ESTADO\n# Implementa las reglas del diagrama de estados oficial\n# ==============================================================\n\nTRANSICIONES_CULTIVO = {\n    "creado":                  {"en_seguimiento", "eliminado"},\n    "en_seguimiento":          {"con_problema_detectado", "finalizado", "eliminado"},\n    "con_problema_detectado":  {"tratamiento_aplicado", "en_seguimiento"},\n    "tratamiento_aplicado":    {"en_seguimiento", "finalizado"},\n    "finalizado":              set(),\n    "eliminado":               set(),\n}\n\nTRANSICIONES_LOTE = {\n    "registrado":   {"disponible", "eliminado"},\n    "disponible":   {"en_analisis", "eliminado"},\n    "en_analisis":  {"aprobado", "con_problema"},\n    "aprobado":     {"vendido"},\n    "con_problema": {"en_analisis", "eliminado"},\n    "vendido":      set(),\n    "eliminado":    set(),\n}\n\n\nclass CultivoService:\n    """Servicio principal para gestion de cultivos y lotes."""\n\n    def __init__(self, db: Session):\n        self.db = db\n\n    # ----------------------------------------------------------\n    # CULTIVOS - RF-03\n    # ----------------------------------------------------------\n\n    def crear_cultivo(\n        self, datos: CultivoCreate, usuario_id: int\n    ) -> Cultivo:\n        """\n        CP-03: registra un nuevo cultivo en estado \'creado\'.\n        Vincula el cultivo al usuario autenticado.\n        """\n        cultivo = Cultivo(\n            nombre_cultivo=datos.nombre_cultivo,\n            ubicacion=datos.ubicacion,\n            area_hectareas=datos.area_hectareas,\n            variedad_cafe=datos.variedad_cafe,\n            fecha_siembra=datos.fecha_siembra,\n            observaciones=datos.observaciones,\n            estado="creado",\n            id_usuario=usuario_id,\n        )\n        self.db.add(cultivo)\n        self.db.commit()\n        self.db.refresh(cultivo)\n        logger.info(\n            f"Cultivo creado: id={cultivo.id_cultivo} "\n            f"nombre=\'{cultivo.nombre_cultivo}\' usuario={usuario_id}"\n        )\n        return cultivo\n\n    def listar_cultivos(self, usuario_id: int) -> List[Cultivo]:\n        """\n        Retorna los cultivos activos del usuario autenticado.\n        No incluye cultivos en estado \'eliminado\'.\n        """\n        return (\n            self.db.query(Cultivo)\n            .filter(\n                Cultivo.id_usuario == usuario_id,\n                Cultivo.estado != "eliminado",\n            )\n            .order_by(Cultivo.fecha_registro.desc())\n            .all()\n        )\n\n    def obtener_cultivo(\n        self, cultivo_id: int, usuario_id: int\n    ) -> Cultivo:\n        """\n        Retorna un cultivo verificando la propiedad del usuario.\n        Lanza HTTP 404 si no existe o no pertenece al usuario.\n        """\n        cultivo = (\n            self.db.query(Cultivo)\n            .filter(\n                Cultivo.id_cultivo == cultivo_id,\n                Cultivo.id_usuario == usuario_id,\n                Cultivo.estado != "eliminado",\n            )\n            .first()\n        )\n        if not cultivo:\n            raise HTTPException(\n                status_code=status.HTTP_404_NOT_FOUND,\n                detail=(\n                    f"Cultivo con id={cultivo_id} no encontrado "\n                    "o no tiene acceso a este recurso"\n                ),\n            )\n        return cultivo\n\n    def actualizar_cultivo(\n        self, cultivo_id: int, datos: CultivoUpdate, usuario_id: int\n    ) -> Cultivo:\n        """\n        Actualiza los datos de un cultivo.\n        Valida la transicion de estado contra el diagrama de estados oficial.\n        """\n        cultivo = self.obtener_cultivo(cultivo_id, usuario_id)\n\n        if datos.estado:\n            self._validar_transicion_cultivo(cultivo.estado, datos.estado)\n\n        campos = datos.model_dump(exclude_unset=True)\n        for campo, valor in campos.items():\n            setattr(cultivo, campo, valor)\n\n        self.db.commit()\n        self.db.refresh(cultivo)\n        logger.info(\n            f"Cultivo actualizado: id={cultivo_id} "\n            f"estado=\'{cultivo.estado}\'"\n        )\n        return cultivo\n\n    def eliminar_cultivo(\n        self, cultivo_id: int, usuario_id: int\n    ) -> None:\n        """\n        RNF-05: eliminacion logica. El cultivo pasa a estado \'eliminado\'.\n        No se borra el registro fisico de la base de datos.\n        """\n        cultivo = self.obtener_cultivo(cultivo_id, usuario_id)\n        cultivo.estado = "eliminado"\n        self.db.commit()\n        logger.info(f"Cultivo eliminado (logico): id={cultivo_id}")\n\n    def resumen_dashboard(self, usuario_id: int) -> ResumenCultivoResponse:\n        """\n        Genera el resumen estadistico para el panel principal\n        del Caficultor con una sola consulta agregada.\n        """\n        cultivos_activos = (\n            self.db.query(func.count(Cultivo.id_cultivo))\n            .filter(\n                Cultivo.id_usuario == usuario_id,\n                Cultivo.estado != "eliminado",\n            )\n            .scalar() or 0\n        )\n\n        area_total = (\n            self.db.query(func.sum(Cultivo.area_hectareas))\n            .filter(\n                Cultivo.id_usuario == usuario_id,\n                Cultivo.estado != "eliminado",\n            )\n            .scalar() or 0.0\n        )\n\n        # Subquery para obtener lotes de los cultivos del usuario\n        # BUG-019 FIX: excluir cultivos eliminados\n        ids_cultivos = (\n            self.db.query(Cultivo.id_cultivo)\n            .filter(\n                Cultivo.id_usuario == usuario_id,\n                Cultivo.estado != "eliminado",\n            )\n            .subquery()\n        )\n\n        total_lotes = (\n            self.db.query(func.count(Lote.id_lote))\n            .filter(Lote.id_cultivo.in_(ids_cultivos))\n            .scalar() or 0\n        )\n\n        lotes_en_proceso = (\n            self.db.query(func.count(Lote.id_lote))\n            .filter(\n                Lote.id_cultivo.in_(ids_cultivos),\n                Lote.estado_lote.in_(["registrado", "disponible", "en_analisis"]),\n            )\n            .scalar() or 0\n        )\n\n        lotes_vendidos = (\n            self.db.query(func.count(Lote.id_lote))\n            .filter(\n                Lote.id_cultivo.in_(ids_cultivos),\n                Lote.estado_lote == "vendido",\n            )\n            .scalar() or 0\n        )\n\n        lotes_con_problema = (\n            self.db.query(func.count(Lote.id_lote))\n            .filter(\n                Lote.id_cultivo.in_(ids_cultivos),\n                Lote.estado_lote == "con_problema",\n            )\n            .scalar() or 0\n        )\n\n        return ResumenCultivoResponse(\n            total_cultivos_activos=cultivos_activos,\n            total_lotes=total_lotes,\n            lotes_en_proceso=lotes_en_proceso,\n            lotes_vendidos=lotes_vendidos,\n            lotes_con_problema=lotes_con_problema,\n            area_total_hectareas=float(area_total),\n        )\n\n    # ----------------------------------------------------------\n    # LOTES - RF-04\n    # ----------------------------------------------------------\n\n    def crear_lote(\n        self, cultivo_id: int, datos: LoteCreate, usuario_id: int\n    ) -> Lote:\n        """\n        CP-04: registra un nuevo lote en estado \'registrado\'.\n        Genera automaticamente el codigo QR para consulta publica (RF-15).\n        Verifica que el usuario sea propietario del cultivo.\n        """\n        self.obtener_cultivo(cultivo_id, usuario_id)\n\n        existente = self.db.query(Lote).filter(\n            Lote.codigo_lote == datos.codigo_lote\n        ).first()\n        if existente:\n            raise HTTPException(\n                status_code=status.HTTP_409_CONFLICT,\n                detail=(\n                    f"Ya existe un lote con el codigo \'{datos.codigo_lote}\'. "\n                    "Use un codigo unico para este lote."\n                ),\n            )\n\n        # Genera token URL-safe de 48 chars para el QR\n        codigo_qr = secrets.token_urlsafe(36)\n\n        lote = Lote(\n            codigo_lote=datos.codigo_lote,\n            codigo_qr=codigo_qr,\n            fecha_cosecha=datos.fecha_cosecha,\n            cantidad_kg=datos.cantidad_kg,\n            observaciones=datos.observaciones,\n            estado_lote="registrado",\n            id_cultivo=cultivo_id,\n        )\n        self.db.add(lote)\n        self.db.commit()\n        self.db.refresh(lote)\n        logger.info(\n            f"Lote creado: id={lote.id_lote} "\n            f"codigo=\'{lote.codigo_lote}\' cultivo={cultivo_id}"\n        )\n        return lote\n\n    def listar_lotes(\n        self, cultivo_id: int, usuario_id: int\n    ) -> List[Lote]:\n        """Retorna los lotes del cultivo que pertenece al usuario."""\n        self.obtener_cultivo(cultivo_id, usuario_id)\n        return (\n            self.db.query(Lote)\n            .filter(\n                Lote.id_cultivo == cultivo_id,\n                Lote.estado_lote != "eliminado",\n            )\n            .order_by(Lote.fecha_registro.desc())\n            .all()\n        )\n\n    def obtener_lote(\n        self, lote_id: int, usuario_id: int\n    ) -> Lote:\n        """Obtiene un lote verificando la cadena de propiedad usuario-cultivo."""\n        lote = (\n            self.db.query(Lote)\n            .join(Cultivo)\n            .filter(\n                Lote.id_lote == lote_id,\n                Cultivo.id_usuario == usuario_id,\n                Lote.estado_lote != "eliminado",\n            )\n            .first()\n        )\n        if not lote:\n            raise HTTPException(\n                status_code=status.HTTP_404_NOT_FOUND,\n                detail=f"Lote con id={lote_id} no encontrado o sin acceso",\n            )\n        return lote\n\n    def actualizar_lote(\n        self, lote_id: int, datos: LoteUpdate, usuario_id: int\n    ) -> Lote:\n        """\n        Actualiza el estado u observaciones de un lote.\n        RN-02: bloquea el paso a \'vendido\' si no hay trazabilidad completa.\n        Valida transiciones segun el diagrama de estados del Lote.\n        """\n        lote = self.obtener_lote(lote_id, usuario_id)\n\n        if datos.estado_lote:\n            self._validar_transicion_lote(lote.estado_lote, datos.estado_lote)\n\n            if datos.estado_lote == "vendido":\n                self._verificar_trazabilidad_rn02(lote_id)\n\n            lote.estado_lote = datos.estado_lote\n\n        if datos.cantidad_kg is not None:\n            lote.cantidad_kg = datos.cantidad_kg\n        if datos.observaciones is not None:\n            lote.observaciones = datos.observaciones\n\n        self.db.commit()\n        self.db.refresh(lote)\n        logger.info(\n            f"Lote actualizado: id={lote_id} estado=\'{lote.estado_lote}\'"\n        )\n        return lote\n\n    def eliminar_lote(\n        self, lote_id: int, usuario_id: int\n    ) -> None:\n        """RNF-05: eliminacion logica del lote."""\n        lote = self.obtener_lote(lote_id, usuario_id)\n        lote.estado_lote = "eliminado"\n        self.db.commit()\n        logger.info(f"Lote eliminado (logico): id={lote_id}")\n\n    # ----------------------------------------------------------\n    # SENSORES - RNF-06, RNF-09\n    # ----------------------------------------------------------\n\n    def registrar_sensor(\n        self, cultivo_id: int, datos: SensorCreate, usuario_id: int\n    ) -> Sensor:\n        """\n        RNF-06: registra un nuevo sensor IoT sin cambios de arquitectura.\n        El sensor queda vinculado al cultivo y empieza en estado \'activo\'.\n        """\n        self.obtener_cultivo(cultivo_id, usuario_id)\n\n        existente = self.db.query(Sensor).filter(\n            Sensor.codigo_sensor == datos.codigo_sensor\n        ).first()\n        if existente:\n            raise HTTPException(\n                status_code=status.HTTP_409_CONFLICT,\n                detail=f"Ya existe un sensor con codigo \'{datos.codigo_sensor}\'",\n            )\n\n        sensor = Sensor(\n            codigo_sensor=datos.codigo_sensor,\n            tipo_sensor=datos.tipo_sensor,\n            descripcion=datos.descripcion,\n            unidad_medida=datos.unidad_medida,\n            fecha_instalacion=datos.fecha_instalacion,\n            estado="activo",\n            id_cultivo=cultivo_id,\n        )\n        self.db.add(sensor)\n        self.db.commit()\n        self.db.refresh(sensor)\n        logger.info(\n            f"Sensor registrado: codigo=\'{sensor.codigo_sensor}\' "\n            f"tipo=\'{sensor.tipo_sensor}\' cultivo={cultivo_id}"\n        )\n        return sensor\n\n    def listar_sensores(\n        self, cultivo_id: int, usuario_id: int\n    ) -> List[Sensor]:\n        self.obtener_cultivo(cultivo_id, usuario_id)\n        return (\n            self.db.query(Sensor)\n            .filter(Sensor.id_cultivo == cultivo_id)\n            .order_by(Sensor.codigo_sensor)\n            .all()\n        )\n\n    # ----------------------------------------------------------\n    # METODOS PRIVADOS\n    # ----------------------------------------------------------\n\n    def _validar_transicion_cultivo(\n        self, estado_actual: str, estado_nuevo: str\n    ) -> None:\n        """\n        Valida que la transicion de estado del cultivo sea\n        coherente con el diagrama de estados oficial del proyecto.\n        """\n        permitidos = TRANSICIONES_CULTIVO.get(estado_actual, set())\n        if estado_nuevo not in permitidos:\n            raise HTTPException(\n                status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,\n                detail=(\n                    f"Transicion invalida en el cultivo: "\n                    f"\'{estado_actual}\' no puede cambiar a \'{estado_nuevo}\'. "\n                    f"Transiciones permitidas: {sorted(permitidos)}"\n                ),\n            )\n\n    def _validar_transicion_lote(\n        self, estado_actual: str, estado_nuevo: str\n    ) -> None:\n        """\n        Valida que la transicion de estado del lote sea coherente\n        con el diagrama de estados oficial del proyecto.\n        """\n        permitidos = TRANSICIONES_LOTE.get(estado_actual, set())\n        if estado_nuevo not in permitidos:\n            raise HTTPException(\n                status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,\n                detail=(\n                    f"Transicion invalida en el lote: "\n                    f"\'{estado_actual}\' no puede cambiar a \'{estado_nuevo}\'. "\n                    f"Transiciones permitidas: {sorted(permitidos)}"\n                ),\n            )\n\n    def _verificar_trazabilidad_rn02(self, lote_id: int) -> None:\n        """\n        RN-02: verifica que el lote tenga registrada la etapa\n        \'comercializacion\' en tbl_trazabilidad antes de pasar a \'vendido\'.\n        Lanza HTTP 422 si la condicion no se cumple.\n        """\n        resultado = self.db.execute(\n            text(\n                "SELECT COUNT(*) FROM tbl_trazabilidad "\n                "WHERE id_lote = :lote_id AND etapa = \'comercializacion\'"\n            ),\n            {"lote_id": lote_id},\n        ).scalar()\n\n        if not resultado:\n            logger.warning(\n                f"RN-02 bloqueado: lote={lote_id} intento pasar a \'vendido\' "\n                "sin trazabilidad completa"\n            )\n            raise HTTPException(\n                status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,\n                detail=(\n                    "RN-02: Este lote no puede marcarse como \'vendido\' todavia. "\n                    "Primero debe registrar la etapa \'comercializacion\' "\n                    "en el modulo de Trazabilidad."\n                ),\n            )\n'

ARCHIVOS["Backend/ia/app/services/ia_service.py"] = '# ==============================================================\n# modulo_04_ia / app/services/ia_service.py\n# Servicio orquestador de todos los modelos de IA\n#\n# Implementa el flujo completo del Diagrama de Secuencia oficial:\n#   1  seleccionarImagen\n#   2  cargarImagen\n#   3  enviarImagen\n#   4  procesarImagen (validaciones)\n#   5  enviarAIA      (llamar motor)\n#   6  analizarImagen (inferencia)\n#   7  generarDiagnostico\n#   8  retornarResultado (construir respuesta)\n#   9  guardarResultado  (persistir en BD)\n#   10 mostrarResultados (retornar al controlador)\n#\n# RN-03: antes de RF-07, RF-08 y RF-09 verifica que los datos\n# del M03 sean frescos consultando tbl_monitoreo_ambiental\n# y tbl_monitoreo_suelo directamente en BD (sin HTTP entre\n# servicios, para mayor resiliencia en zonas rurales).\n# ==============================================================\n\nimport json\nimport logging\nfrom datetime import datetime, timezone, timedelta\nfrom typing import List, Optional\n\nfrom fastapi import HTTPException, UploadFile, status\nfrom sqlalchemy import text\nfrom sqlalchemy.orm import Session\n\nfrom app.core.config import settings\nfrom app.ia.motor.clasificador_imagen import (\n    ClasificadorImagen, obtener_recomendacion,\n)\nfrom app.ia.motor.predictor_fitosanitario import (\n    predecir_riesgo, generar_recomendacion_fito,\n)\nfrom app.ia.motor.recomendador_riego import recomendar_riego\nfrom app.ia.motor.recomendador_fertilizacion import recomendar_fertilizacion\nfrom app.models.analisis import (\n    AnalisisImagen, PrediccionFitosanitaria,\n    RecomendacionRiego, RecomendacionFertilizacion,\n)\nfrom app.schemas.analisis import (\n    AnalisisImagenResponse, HistorialAnalisisResponse,\n    PrediccionFitoResponse, RecomendacionRiegoResponse,\n    RecomendacionFertResponse, ResumenIAResponse,\n    ClaseConfianza,\n)\n\nlogger = logging.getLogger(__name__)\n\n# Tipos de imagen permitidos (RNF-01)\nTIPOS_PERMITIDOS = set(settings.IMAGEN_TIPOS_PERMITIDOS.split(","))\n\n\nclass IAService:\n    """\n    Servicio principal del Modulo 04.\n    Orquesta los cuatro motores de IA y gestiona la persistencia\n    de todos los resultados en la base de datos.\n    """\n\n    def __init__(self, db: Session):\n        self.db = db\n\n    # ----------------------------------------------------------\n    # UTILIDADES INTERNAS\n    # ----------------------------------------------------------\n\n    def _verificar_acceso_cultivo(self, cultivo_id: int, usuario_id: int) -> None:\n        r = self.db.execute(\n            text(\n                "SELECT id_cultivo FROM tbl_cultivo "\n                "WHERE id_cultivo = :c AND id_usuario = :u "\n                "AND estado != \'eliminado\'"\n            ),\n            {"c": cultivo_id, "u": usuario_id},\n        ).fetchone()\n        if not r:\n            raise HTTPException(\n                status_code=status.HTTP_404_NOT_FOUND,\n                detail=f"Cultivo {cultivo_id} no encontrado o sin acceso.",\n            )\n\n    def _obtener_ultima_ambiental(self, cultivo_id: int) -> Optional[dict]:\n        """Consulta la ultima lectura ambiental directamente en BD."""\n        r = self.db.execute(\n            text(\n                "SELECT temperatura, humedad_relativa, precipitacion_mm, "\n                "fecha_registro "\n                "FROM tbl_monitoreo_ambiental "\n                "WHERE id_cultivo = :c "\n                "ORDER BY fecha_registro DESC LIMIT 1"\n            ),\n            {"c": cultivo_id},\n        ).fetchone()\n        return dict(r._mapping) if r else None\n\n    def _obtener_ultima_suelo(self, cultivo_id: int) -> Optional[dict]:\n        """Consulta la ultima lectura de suelo directamente en BD."""\n        r = self.db.execute(\n            text(\n                "SELECT ph, humedad_suelo, nitrogeno, fosforo, potasio, "\n                "materia_organica, fecha_registro "\n                "FROM tbl_monitoreo_suelo "\n                "WHERE id_cultivo = :c "\n                "ORDER BY fecha_registro DESC LIMIT 1"\n            ),\n            {"c": cultivo_id},\n        ).fetchone()\n        return dict(r._mapping) if r else None\n\n    def _verificar_rn03(\n        self,\n        cultivo_id:       int,\n        requiere_ambiental: bool = True,\n        requiere_suelo:     bool = True,\n    ) -> tuple:\n        """\n        RN-03: verifica que los datos del M03 sean validos (< 24h).\n        Lanza HTTP 422 con mensaje claro si los datos estan caducados.\n        Retorna (datos_ambiental, datos_suelo).\n        """\n        limite    = timedelta(hours=settings.HORAS_DATOS_VALIDOS)\n        ahora     = datetime.now(timezone.utc)\n        amb       = None\n        sue       = None\n\n        if requiere_ambiental:\n            amb = self._obtener_ultima_ambiental(cultivo_id)\n            if not amb:\n                raise HTTPException(\n                    status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,\n                    detail=(\n                        "RN-03: No existen datos ambientales registrados para este cultivo. "\n                        "Registre al menos una lectura en el Modulo de Monitoreo antes "\n                        "de solicitar recomendaciones de IA."\n                    ),\n                )\n            fecha = amb["fecha_registro"]\n            if fecha.tzinfo is None:\n                fecha = fecha.replace(tzinfo=timezone.utc)\n            horas = (ahora - fecha).total_seconds() / 3600\n            if horas > settings.HORAS_DATOS_VALIDOS:\n                raise HTTPException(\n                    status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,\n                    detail=(\n                        f"RN-03: Los datos ambientales tienen {horas:.1f} horas de antiguedad "\n                        f"(maximo permitido: {settings.HORAS_DATOS_VALIDOS}h). "\n                        "Registre una nueva lectura ambiental para habilitar la IA."\n                    ),\n                )\n\n        if requiere_suelo:\n            sue = self._obtener_ultima_suelo(cultivo_id)\n            if not sue:\n                raise HTTPException(\n                    status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,\n                    detail=(\n                        "RN-03: No existen datos de suelo registrados para este cultivo. "\n                        "Registre al menos una lectura de suelo en el Modulo de Monitoreo."\n                    ),\n                )\n            fecha = sue["fecha_registro"]\n            if fecha.tzinfo is None:\n                fecha = fecha.replace(tzinfo=timezone.utc)\n            horas = (ahora - fecha).total_seconds() / 3600\n            if horas > settings.HORAS_DATOS_VALIDOS:\n                raise HTTPException(\n                    status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,\n                    detail=(\n                        f"RN-03: Los datos de suelo tienen {horas:.1f} horas de antiguedad "\n                        f"(maximo permitido: {settings.HORAS_DATOS_VALIDOS}h). "\n                        "Registre una nueva lectura de suelo para habilitar la IA."\n                    ),\n                )\n\n        return amb, sue\n\n    # ----------------------------------------------------------\n    # RF-05 y RF-06 - ANALISIS DE IMAGEN\n    # ----------------------------------------------------------\n\n    async def analizar_imagen(\n        self,\n        cultivo_id:  int,\n        usuario_id:  int,\n        tipo:        str,         # \'enfermedad\' | \'plaga\'\n        imagen:      UploadFile,\n    ) -> AnalisisImagenResponse:\n        """\n        Flujo completo segun Diagrama de Secuencia (pasos 3-10):\n          Paso 3  enviarImagen    - recibir archivo\n          Paso 4  procesarImagen  - validar formato y tamano\n          Paso 5  enviarAIA       - llamar al clasificador\n          Paso 6  analizarImagen  - inferencia CNN\n          Paso 7  generarDiag     - construir diagnostico\n          Paso 8  retornarResult  - montar respuesta\n          Paso 9  guardarResult   - persistir en BD\n          Paso 10 mostrarResult   - retornar al controlador\n        """\n        self._verificar_acceso_cultivo(cultivo_id, usuario_id)\n\n        # ---- Paso 4: validar imagen ----\n        content_type = imagen.content_type or ""\n        if content_type not in TIPOS_PERMITIDOS:\n            raise HTTPException(\n                status_code=status.HTTP_415_UNSUPPORTED_MEDIA_TYPE,\n                detail=(\n                    f"Tipo de archivo \'{content_type}\' no permitido. "\n                    f"Use: {\', \'.join(TIPOS_PERMITIDOS)}"\n                ),\n            )\n\n        imagen_bytes = await imagen.read()\n        tamano_kb    = len(imagen_bytes) // 1024\n\n        if len(imagen_bytes) > settings.IMAGEN_MAX_BYTES:\n            raise HTTPException(\n                status_code=status.HTTP_413_REQUEST_ENTITY_TOO_LARGE,\n                detail=(\n                    f"Imagen demasiado grande ({tamano_kb} KB). "\n                    f"Maximo permitido: {settings.IMAGEN_MAX_BYTES // 1024} KB."\n                ),\n            )\n\n        if len(imagen_bytes) < 1000:\n            raise HTTPException(\n                status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,\n                detail="La imagen parece estar vacia o corrupta (< 1 KB).",\n            )\n\n        # ---- Pasos 5-7: inferencia ----\n        try:\n            clasificador = ClasificadorImagen(tipo)\n            diagnostico, confianza, top_raw, tiempo = clasificador.analizar(\n                imagen_bytes, imagen.filename or ""\n            )\n        except TimeoutError as e:\n            raise HTTPException(\n                status_code=status.HTTP_504_GATEWAY_TIMEOUT,\n                detail=str(e),\n            )\n\n        # Verificar umbral de confianza\n        if confianza < settings.UMBRAL_CONFIANZA_MINIMA:\n            diagnostico = "sano"\n            confianza   = confianza\n            logger.warning(\n                f"Confianza {confianza:.3f} por debajo del umbral "\n                f"{settings.UMBRAL_CONFIANZA_MINIMA}. Reportando como \'sano\'."\n            )\n\n        recomendacion, urgencia = obtener_recomendacion(tipo, diagnostico)\n\n        # ---- Paso 9: guardar en BD ----\n        registro = AnalisisImagen(\n            tipo_analisis     = tipo,\n            diagnostico       = diagnostico,\n            confianza         = confianza,\n            top_clases        = json.dumps(top_raw, ensure_ascii=False),\n            recomendacion     = recomendacion,\n            nivel_urgencia    = urgencia,\n            version_modelo    = clasificador.version,\n            tiempo_inferencia = tiempo,\n            nombre_imagen     = imagen.filename,\n            tamano_imagen_kb  = tamano_kb,\n            id_cultivo        = cultivo_id,\n            id_usuario        = usuario_id,\n        )\n        self.db.add(registro)\n\n        # Actualizar estado del cultivo si se detecta un problema (Diagrama Estados)\n        if diagnostico != "sano" and urgencia in ("alto", "critico"):\n            self.db.execute(\n                text(\n                    # BUG-020 FIX: verificar propietario antes de actualizar\n                    "UPDATE tbl_cultivo SET estado = \'con_problema_detectado\' "\n                    "WHERE id_cultivo = :c AND id_usuario = :u AND estado = \'en_seguimiento\'"\n                ),\n                {"c": cultivo_id, "u": usuario_id},\n            )\n\n        self.db.commit()\n        self.db.refresh(registro)\n\n        # ---- Paso 10: construir respuesta ----\n        top_clases = [\n            ClaseConfianza(clase=t["clase"], probabilidad=t["probabilidad"])\n            for t in top_raw\n        ]\n\n        return AnalisisImagenResponse(\n            id_analisis       = registro.id_analisis,\n            tipo_analisis     = tipo,\n            diagnostico       = diagnostico,\n            confianza         = round(confianza, 4),\n            confianza_pct     = f"{confianza * 100:.1f}%",\n            top_clases        = top_clases,\n            recomendacion     = recomendacion,\n            nivel_urgencia    = urgencia,\n            version_modelo    = registro.version_modelo,\n            tiempo_inferencia = round(tiempo, 3),\n            tiempo_pct_rnf01  = f"{tiempo:.2f}s de {settings.TIMEOUT_INFERENCIA_SEG}s permitidos",\n            nombre_imagen     = registro.nombre_imagen,\n            fecha_analisis    = registro.fecha_analisis,\n            id_cultivo        = cultivo_id,\n        )\n\n    def historial_analisis(\n        self,\n        cultivo_id: int,\n        usuario_id: int,\n        tipo:       Optional[str] = None,\n        limite:     int = 20,\n    ) -> List[HistorialAnalisisResponse]:\n        """CP-07: historial de analisis del cultivo."""\n        self._verificar_acceso_cultivo(cultivo_id, usuario_id)\n        limite  = min(limite, 200)\n        q = (\n            self.db.query(AnalisisImagen)\n            .filter(AnalisisImagen.id_cultivo == cultivo_id)\n        )\n        if tipo:\n            q = q.filter(AnalisisImagen.tipo_analisis == tipo)\n        registros = q.order_by(AnalisisImagen.fecha_analisis.desc()).limit(limite).all()\n        return [\n            HistorialAnalisisResponse(\n                id_analisis    = r.id_analisis,\n                tipo_analisis  = r.tipo_analisis,\n                diagnostico    = r.diagnostico,\n                confianza      = r.confianza,\n                nivel_urgencia = r.nivel_urgencia,\n                fecha_analisis = r.fecha_analisis,\n                id_cultivo     = r.id_cultivo,\n            )\n            for r in registros\n        ]\n\n    # ----------------------------------------------------------\n    # RF-07 - PREDICCION FITOSANITARIA\n    # ----------------------------------------------------------\n\n    def predecir_fitosanitario(\n        self, cultivo_id: int, usuario_id: int\n    ) -> PrediccionFitoResponse:\n        """\n        RF-07 + RN-03: predice riesgo fitosanitario usando datos\n        ambientales actualizados del cultivo.\n        """\n        self._verificar_acceso_cultivo(cultivo_id, usuario_id)\n        amb, _ = self._verificar_rn03(cultivo_id, requiere_ambiental=True, requiere_suelo=False)\n\n        temp  = float(amb["temperatura"])      if amb.get("temperatura")      else None\n        hum   = float(amb["humedad_relativa"]) if amb.get("humedad_relativa") else None\n        prec  = float(amb["precipitacion_mm"]) if amb.get("precipitacion_mm") else None\n\n        nivel, prob, factores, enf_prob = predecir_riesgo(temp, hum, prec)\n        reco = generar_recomendacion_fito(nivel, factores)\n\n        registro = PrediccionFitosanitaria(\n            nivel_riesgo         = nivel,\n            probabilidad_riesgo  = prob,\n            factores_riesgo      = json.dumps(factores,   ensure_ascii=False),\n            enfermedades_prob    = json.dumps(enf_prob,   ensure_ascii=False),\n            recomendacion        = reco,\n            temperatura_usada    = temp,\n            humedad_usada        = hum,\n            precipitacion_usada  = prec,\n            version_modelo       = "reglas-cenicafe-1.0",\n            id_cultivo           = cultivo_id,\n            id_usuario           = usuario_id,\n        )\n        self.db.add(registro)\n        self.db.commit()\n        self.db.refresh(registro)\n\n        return PrediccionFitoResponse(\n            id_prediccion        = registro.id_prediccion,\n            nivel_riesgo         = nivel,\n            probabilidad_riesgo  = prob,\n            probabilidad_pct     = f"{prob * 100:.1f}%",\n            factores_riesgo      = factores,\n            enfermedades_prob    = enf_prob,\n            recomendacion        = reco,\n            temperatura_usada    = temp,\n            humedad_usada        = hum,\n            precipitacion_usada  = prec,\n            fecha_prediccion     = registro.fecha_prediccion,\n            id_cultivo           = cultivo_id,\n        )\n\n    # ----------------------------------------------------------\n    # RF-08 - RECOMENDACION DE RIEGO\n    # ----------------------------------------------------------\n\n    def recomendar_riego(\n        self, cultivo_id: int, usuario_id: int\n    ) -> RecomendacionRiegoResponse:\n        """\n        RF-08 + RN-03: genera recomendacion de riego usando\n        datos de suelo y ambientales actualizados.\n        """\n        self._verificar_acceso_cultivo(cultivo_id, usuario_id)\n        amb, sue = self._verificar_rn03(cultivo_id, True, True)\n\n        hum_suelo = float(sue["humedad_suelo"]) if sue and sue.get("humedad_suelo") else None\n        temp      = float(amb["temperatura"])    if amb and amb.get("temperatura")   else None\n        prec      = float(amb["precipitacion_mm"]) if amb and amb.get("precipitacion_mm") else None\n\n        necesita, cantidad, frecuencia, momento, justif, reco, urgencia = recomendar_riego(\n            hum_suelo, temp, prec\n        )\n\n        registro = RecomendacionRiego(\n            necesita_riego      = necesita,\n            cantidad_litros_m2  = cantidad,\n            frecuencia_dias     = frecuencia,\n            momento_optimo      = momento,\n            justificacion       = justif,\n            recomendacion       = reco,\n            nivel_urgencia      = urgencia,\n            humedad_suelo_usada = hum_suelo,\n            temperatura_usada   = temp,\n            precipitacion_usada = prec,\n            version_modelo      = "reglas-cenicafe-riego-1.0",\n            id_cultivo          = cultivo_id,\n            id_usuario          = usuario_id,\n        )\n        self.db.add(registro)\n        self.db.commit()\n        self.db.refresh(registro)\n\n        return RecomendacionRiegoResponse(\n            id_reco             = registro.id_reco,\n            necesita_riego      = necesita,\n            cantidad_litros_m2  = float(cantidad) if cantidad else None,\n            frecuencia_dias     = frecuencia,\n            momento_optimo      = momento,\n            justificacion       = justif,\n            recomendacion       = reco,\n            nivel_urgencia      = urgencia,\n            humedad_suelo_usada = hum_suelo,\n            temperatura_usada   = temp,\n            precipitacion_usada = prec,\n            fecha_recomendacion = registro.fecha_recomendacion,\n            id_cultivo          = cultivo_id,\n        )\n\n    # ----------------------------------------------------------\n    # RF-09 - RECOMENDACION DE FERTILIZACION\n    # ----------------------------------------------------------\n\n    def recomendar_fertilizacion(\n        self, cultivo_id: int, usuario_id: int\n    ) -> RecomendacionFertResponse:\n        """\n        RF-09 + RN-03: genera recomendacion de fertilizacion\n        basada en el estado quimico del suelo.\n        """\n        self._verificar_acceso_cultivo(cultivo_id, usuario_id)\n        _, sue = self._verificar_rn03(cultivo_id, requiere_ambiental=False, requiere_suelo=True)\n\n        ph   = float(sue["ph"])               if sue and sue.get("ph")               else None\n        n    = float(sue["nitrogeno"])         if sue and sue.get("nitrogeno")         else None\n        p    = float(sue["fosforo"])           if sue and sue.get("fosforo")           else None\n        k    = float(sue["potasio"])           if sue and sue.get("potasio")           else None\n        mo   = float(sue["materia_organica"])  if sue and sue.get("materia_organica")  else None\n\n        tipo_f, dosis, frecuencia, metodo, defic, justif, reco, urgencia = recomendar_fertilizacion(\n            ph, n, p, k, mo\n        )\n\n        registro = RecomendacionFertilizacion(\n            tipo_fertilizante        = tipo_f,\n            dosis_kg_ha              = dosis,\n            frecuencia_aplicacion    = frecuencia,\n            metodo_aplicacion        = metodo,\n            nutrientes_deficientes   = json.dumps(defic, ensure_ascii=False),\n            justificacion            = justif,\n            recomendacion            = reco,\n            nivel_urgencia           = urgencia,\n            ph_suelo_usado           = ph,\n            nitrogeno_usado          = n,\n            fosforo_usado            = p,\n            potasio_usado            = k,\n            materia_organica_usada   = mo,\n            version_modelo           = "reglas-cenicafe-fert-1.0",\n            id_cultivo               = cultivo_id,\n            id_usuario               = usuario_id,\n        )\n        self.db.add(registro)\n        self.db.commit()\n        self.db.refresh(registro)\n\n        return RecomendacionFertResponse(\n            id_reco_fert              = registro.id_reco_fert,\n            tipo_fertilizante         = tipo_f,\n            dosis_kg_ha               = float(dosis) if dosis else None,\n            frecuencia_aplicacion     = frecuencia,\n            metodo_aplicacion         = metodo,\n            nutrientes_deficientes    = defic,\n            justificacion             = justif,\n            recomendacion             = reco,\n            nivel_urgencia            = urgencia,\n            ph_suelo_usado            = ph,\n            nitrogeno_usado           = n,\n            fosforo_usado             = p,\n            potasio_usado             = k,\n            materia_organica_usada    = mo,\n            fecha_recomendacion       = registro.fecha_recomendacion,\n            id_cultivo                = cultivo_id,\n        )\n\n    # ----------------------------------------------------------\n    # RESUMEN DASHBOARD IA\n    # ----------------------------------------------------------\n\n    def resumen_ia(self, cultivo_id: int, usuario_id: int) -> ResumenIAResponse:\n        """Panel consolidado del Caficultor con el estado de todos los modulos IA."""\n        self._verificar_acceso_cultivo(cultivo_id, usuario_id)\n\n        alertas            = []\n        datos_validos      = False\n        mensaje_rn03       = "Verifique los datos de monitoreo."\n\n        # Verificar validez RN-03 sin lanzar excepcion\n        try:\n            amb = self._obtener_ultima_ambiental(cultivo_id)\n            sue = self._obtener_ultima_suelo(cultivo_id)\n            limite = timedelta(hours=settings.HORAS_DATOS_VALIDOS)\n            ahora  = datetime.now(timezone.utc)\n            amb_ok = False\n            sue_ok = False\n\n            if amb:\n                fecha = amb["fecha_registro"]\n                if fecha.tzinfo is None:\n                    fecha = fecha.replace(tzinfo=timezone.utc)\n                amb_ok = (ahora - fecha) <= limite\n\n            if sue:\n                fecha = sue["fecha_registro"]\n                if fecha.tzinfo is None:\n                    fecha = fecha.replace(tzinfo=timezone.utc)\n                sue_ok = (ahora - fecha) <= limite\n\n            datos_validos = amb_ok and sue_ok\n            if datos_validos:\n                mensaje_rn03 = "Datos actualizados. Todos los modelos de IA disponibles."\n            else:\n                mensaje_rn03 = (\n                    "Datos desactualizados (> 24h). "\n                    "Registre lecturas nuevas para habilitar recomendaciones de IA."\n                )\n                alertas.append("RN-03: Datos de monitoreo desactualizados")\n        except Exception:\n            pass\n\n        # Ultimo analisis enfermedad\n        ult_enf = (\n            self.db.query(AnalisisImagen)\n            .filter(\n                AnalisisImagen.id_cultivo   == cultivo_id,\n                AnalisisImagen.tipo_analisis == "enfermedad",\n            )\n            .order_by(AnalisisImagen.fecha_analisis.desc())\n            .first()\n        )\n\n        # Ultimo analisis plaga\n        ult_pla = (\n            self.db.query(AnalisisImagen)\n            .filter(\n                AnalisisImagen.id_cultivo   == cultivo_id,\n                AnalisisImagen.tipo_analisis == "plaga",\n            )\n            .order_by(AnalisisImagen.fecha_analisis.desc())\n            .first()\n        )\n\n        # Ultima prediccion fito\n        ult_fito = (\n            self.db.query(PrediccionFitosanitaria)\n            .filter(PrediccionFitosanitaria.id_cultivo == cultivo_id)\n            .order_by(PrediccionFitosanitaria.fecha_prediccion.desc())\n            .first()\n        )\n\n        # Ultima reco riego\n        ult_riego = (\n            self.db.query(RecomendacionRiego)\n            .filter(RecomendacionRiego.id_cultivo == cultivo_id)\n            .order_by(RecomendacionRiego.fecha_recomendacion.desc())\n            .first()\n        )\n\n        # Ultima reco fertilizacion\n        ult_fert = (\n            self.db.query(RecomendacionFertilizacion)\n            .filter(RecomendacionFertilizacion.id_cultivo == cultivo_id)\n            .order_by(RecomendacionFertilizacion.fecha_recomendacion.desc())\n            .first()\n        )\n\n        # Alertas activas\n        if ult_enf and ult_enf.nivel_urgencia in ("alto", "critico"):\n            alertas.append(\n                f"Enfermedad detectada: {ult_enf.diagnostico} "\n                f"(confianza {ult_enf.confianza * 100:.0f}%)"\n            )\n        if ult_pla and ult_pla.nivel_urgencia in ("alto", "critico"):\n            alertas.append(\n                f"Plaga detectada: {ult_pla.diagnostico} "\n                f"(confianza {ult_pla.confianza * 100:.0f}%)"\n            )\n        if ult_fito and ult_fito.nivel_riesgo in ("alto", "critico"):\n            alertas.append(\n                f"Riesgo fitosanitario {ult_fito.nivel_riesgo.upper()}"\n            )\n        if ult_riego and ult_riego.necesita_riego == "si" and ult_riego.nivel_urgencia == "alto":\n            alertas.append("Riego urgente requerido")\n\n        return ResumenIAResponse(\n            cultivo_id                = cultivo_id,\n            datos_validos_rn03        = datos_validos,\n            mensaje_rn03              = mensaje_rn03,\n            ultimo_dx_enfermedad      = ult_enf.diagnostico        if ult_enf  else None,\n            ultima_conf_enfermedad    = ult_enf.confianza           if ult_enf  else None,\n            ultimo_dx_plaga           = ult_pla.diagnostico         if ult_pla  else None,\n            ultima_conf_plaga         = ult_pla.confianza           if ult_pla  else None,\n            ultimo_nivel_riesgo       = ult_fito.nivel_riesgo       if ult_fito else None,\n            ultima_reco_riego         = ult_riego.necesita_riego    if ult_riego else None,\n            ultimo_fertilizante       = ult_fert.tipo_fertilizante  if ult_fert  else None,\n            alertas                   = alertas,\n            fecha_ultimo_analisis_img = ult_enf.fecha_analisis           if ult_enf  else None,\n            fecha_ultima_prediccion   = ult_fito.fecha_prediccion         if ult_fito else None,\n            fecha_ultima_reco_riego   = ult_riego.fecha_recomendacion     if ult_riego else None,\n            fecha_ultima_reco_fert    = ult_fert.fecha_recomendacion      if ult_fert  else None,\n        )\n'

ARCHIVOS["Backend/mercado/app/services/mercado_service.py"] = '# ==============================================================\n# modulo_06_mercado / app/services/mercado_service.py\n# Servicio principal — RF-13 y RF-14\n#\n# Orquesta:\n#   registrar_precio()        Guardar precio de referencia manual\n#   sincronizar_ventas_propias() Importar precios desde M05\n#   analizar_precios()        Ejecutar análisis estadístico RF-13\n#   historial_precios()       Histórico mensual para gráficas\n#   analizar_demanda()        Ejecutar análisis de demanda RF-14\n#   dashboard_mercado()       Panel consolidado Comercializador\n#\n# FUENTE DE DATOS INTERNA (M05):\n#   El servicio consulta tbl_trazabilidad_lote directamente para\n#   obtener precios reales de venta y métricas de demanda.\n#   Esto garantiza coherencia y no requiere sincronización manual.\n# ==============================================================\n\nimport json\nimport logging\nfrom datetime import datetime, timedelta\nfrom typing import List, Optional\n\nfrom fastapi import HTTPException, status\nfrom sqlalchemy import func, text\nfrom sqlalchemy.orm import Session\n\nfrom app.analisis.motor_mercado import (\n    calcular_estadisticas_precios,\n    calcular_variacion_porcentual,\n    clasificar_nivel_demanda,\n    clasificar_tendencia,\n    formatear_variacion_label,\n    generar_alerta_precio,\n    generar_recomendacion_demanda,\n    generar_recomendacion_precio,\n    proyectar_wma3,\n    ICONOS_TENDENCIA,\n    NIVEL_DEMANDA_LABELS,\n)\nfrom app.core.config import settings\nfrom app.models.mercado import AnalisisDemanda, AnalisisPrecio, PrecioMercado\nfrom app.schemas.mercado import (\n    AnalisisDemandaResponse,\n    AnalisisPrecioResponse,\n    DashboardMercadoResponse,\n    DemandaObservacionCreate,\n    HistorialPrecioItem,\n    PrecioCreate,\n    PrecioResponse,\n)\n\nlogger = logging.getLogger(__name__)\n\n\nclass MercadoService:\n\n    def __init__(self, db: Session):\n        self.db = db\n\n    # ----------------------------------------------------------\n    # RF-13 — REGISTRO Y ANÁLISIS DE PRECIOS\n    # ----------------------------------------------------------\n\n    def registrar_precio(\n        self, datos: PrecioCreate, usuario_id: int\n    ) -> PrecioResponse:\n        """Registra un precio de referencia de mercado."""\n        precio = PrecioMercado(\n            fuente            = datos.fuente,\n            tipo_cafe         = datos.tipo_cafe,\n            precio_cop_kg     = datos.precio_cop_kg,\n            precio_usd_lb     = datos.precio_usd_lb,\n            variedad          = datos.variedad,\n            categoria_calidad = datos.categoria_calidad,\n            region            = datos.region,\n            notas             = datos.notas,\n            fecha_precio      = datos.fecha_precio,\n            id_usuario        = usuario_id,\n        )\n        self.db.add(precio)\n        self.db.commit()\n        self.db.refresh(precio)\n        logger.info(f"Precio registrado: {datos.fuente} ${datos.precio_cop_kg}/kg")\n        return self._precio_a_response(precio)\n\n    def sincronizar_ventas_propias(self, usuario_id: int) -> int:\n        """\n        RF-13: importa precios reales de ventas registradas en M05\n        (tbl_trazabilidad_lote) que aún no están en tbl_precio_mercado.\n        Retorna la cantidad de registros nuevos importados.\n        """\n        try:\n            ventas = self.db.execute(\n                text("""\n                    SELECT id_lote, codigo_lote, precio_venta_kg,\n                           clasificacion_calidad, variedad_cafe,\n                           fecha_venta, id_usuario_creador\n                    FROM   tbl_trazabilidad_lote\n                    WHERE  estado = \'vendido\'\n                      AND  precio_venta_kg IS NOT NULL\n                      AND  id_lote NOT IN (\n                               SELECT COALESCE(id_lote_origen, 0)\n                               FROM   tbl_precio_mercado\n                               WHERE  fuente = \'propio_sistema\'\n                                 AND  id_lote_origen IS NOT NULL\n                           )\n                """)\n            ).fetchall()\n        except Exception as e:\n            logger.warning(f"No se pudo consultar tbl_trazabilidad_lote: {e}")\n            return 0\n\n        importados = 0\n        for v in ventas:\n            if v.precio_venta_kg and v.fecha_venta:\n                registro = PrecioMercado(\n                    fuente            = "propio_sistema",\n                    tipo_cafe         = "pergamino_seco",\n                    precio_cop_kg     = float(v.precio_venta_kg),\n                    categoria_calidad = v.clasificacion_calidad or "todas",\n                    variedad          = v.variedad_cafe,\n                    notas             = f"Importado automáticamente del lote {v.codigo_lote}",\n                    id_lote_origen    = v.id_lote,\n                    id_usuario        = usuario_id,\n                    fecha_precio      = v.fecha_venta,\n                )\n                self.db.add(registro)\n                importados += 1\n\n        if importados:\n            self.db.commit()\n            logger.info(f"Sincronizados {importados} precios propios del sistema")\n        return importados\n\n    def listar_precios(\n        self,\n        usuario_id: int,\n        fuente:     Optional[str] = None,\n        meses:      int           = 6,\n    ) -> List[PrecioResponse]:\n        """Lista el histórico de precios con filtros opcionales."""\n        desde = datetime.utcnow() - timedelta(days=meses * 30)\n        q = self.db.query(PrecioMercado).filter(\n            PrecioMercado.fecha_precio >= desde\n        )\n        if fuente:\n            q = q.filter(PrecioMercado.fuente == fuente)\n        precios = q.order_by(PrecioMercado.fecha_precio.desc()).all()\n        return [self._precio_a_response(p) for p in precios]\n\n    def analizar_precios(\n        self,\n        usuario_id:    int,\n        meses:         int = None,\n        tipo_cafe:     str = "pergamino_seco",\n        fuente_filtro: str = "todas",\n    ) -> AnalisisPrecioResponse:\n        """\n        RF-13: ejecuta el análisis estadístico de precios del período.\n\n        Pasos:\n          1. Sincronizar ventas propias del M05\n          2. Obtener precios del período actual\n          3. Obtener precios del período anterior (para variación)\n          4. Calcular estadísticas: media, min, max, rango\n          5. Calcular variación y proyección WMA-3\n          6. Clasificar tendencia y generar alertas\n          7. Persistir el análisis y retornarlo\n        """\n        meses_analisis = meses or settings.MESES_HISTORICO_PRECIO\n\n        # Paso 1: sincronizar ventas propias\n        self.sincronizar_ventas_propias(usuario_id)\n\n        ahora    = datetime.utcnow()\n        inicio   = ahora - timedelta(days=meses_analisis * 30)\n        inicio_a = inicio - timedelta(days=meses_analisis * 30)  # período anterior\n\n        # Paso 2: precios período actual\n        q = self.db.query(PrecioMercado).filter(\n            PrecioMercado.fecha_precio >= inicio,\n            PrecioMercado.tipo_cafe   == tipo_cafe,\n        )\n        if fuente_filtro and fuente_filtro != "todas":\n            q = q.filter(PrecioMercado.fuente == fuente_filtro)\n        registros_actuales = q.all()\n\n        if not registros_actuales:\n            raise HTTPException(\n                status_code=status.HTTP_404_NOT_FOUND,\n                detail=(\n                    f"Sin datos de precios en los últimos {meses_analisis} meses "\n                    f"para tipo \'{tipo_cafe}\'. "\n                    "Registre precios de referencia primero."\n                ),\n            )\n\n        precios_actuales = [float(r.precio_cop_kg) for r in registros_actuales]\n        prom, mini, maxi, rango = calcular_estadisticas_precios(precios_actuales)\n\n        # Paso 3: precios período anterior\n        q_ant = self.db.query(PrecioMercado).filter(\n            PrecioMercado.fecha_precio >= inicio_a,\n            PrecioMercado.fecha_precio <  inicio,\n            PrecioMercado.tipo_cafe    == tipo_cafe,\n        )\n        if fuente_filtro and fuente_filtro != "todas":\n            q_ant = q_ant.filter(PrecioMercado.fuente == fuente_filtro)\n        registros_anteriores = q_ant.all()\n\n        prom_anterior = None\n        if registros_anteriores:\n            precios_ant   = [float(r.precio_cop_kg) for r in registros_anteriores]\n            prom_anterior = sum(precios_ant) / len(precios_ant)\n\n        # Paso 4-5: variación y proyección\n        variacion = calcular_variacion_porcentual(prom, prom_anterior)\n\n        # WMA-3: construir serie mensual de promedios para proyectar\n        serie_mensual = self._serie_mensual_precios(tipo_cafe, fuente_filtro, 3)\n        proyectado    = proyectar_wma3(serie_mensual)\n\n        # Paso 6: tendencia y alertas\n        tendencia               = clasificar_tendencia(variacion, rango, prom)\n        alerta_activa, msg_alerta = generar_alerta_precio(variacion, prom, tendencia)\n        recomendacion, interpretacion = generar_recomendacion_precio(\n            tendencia, variacion, prom, settings.PRECIO_BASE_FNC_COP, proyectado\n        )\n\n        # Paso 7: persistir\n        analisis = AnalisisPrecio(\n            periodo_inicio     = inicio,\n            periodo_fin        = ahora,\n            tipo_cafe          = tipo_cafe,\n            fuente_analizada   = fuente_filtro,\n            precio_promedio    = prom,\n            precio_minimo      = mini,\n            precio_maximo      = maxi,\n            variacion_pct      = variacion,\n            tendencia          = tendencia,\n            precio_proyectado  = proyectado,\n            alerta_activa      = alerta_activa,\n            mensaje_alerta     = msg_alerta,\n            recomendacion      = recomendacion,\n            num_registros_base = len(registros_actuales),\n            id_usuario         = usuario_id,\n        )\n        self.db.add(analisis)\n        self.db.commit()\n        self.db.refresh(analisis)\n\n        logger.info(\n            f"Análisis de precios generado: tendencia={tendencia} "\n            f"prom=${prom} alerta={alerta_activa}"\n        )\n\n        return AnalisisPrecioResponse(\n            id_analisis        = analisis.id_analisis,\n            periodo_inicio     = analisis.periodo_inicio,\n            periodo_fin        = analisis.periodo_fin,\n            tipo_cafe          = analisis.tipo_cafe,\n            fuente_analizada   = analisis.fuente_analizada,\n            precio_promedio    = float(analisis.precio_promedio),\n            precio_minimo      = float(analisis.precio_minimo),\n            precio_maximo      = float(analisis.precio_maximo),\n            rango_precios      = rango,\n            variacion_pct      = analisis.variacion_pct,\n            variacion_label    = formatear_variacion_label(variacion),\n            tendencia          = analisis.tendencia,\n            tendencia_icono    = ICONOS_TENDENCIA.get(tendencia, "→"),\n            precio_proyectado  = float(analisis.precio_proyectado) if analisis.precio_proyectado else None,\n            alerta_activa      = analisis.alerta_activa,\n            mensaje_alerta     = analisis.mensaje_alerta,\n            recomendacion      = analisis.recomendacion,\n            num_registros_base = analisis.num_registros_base,\n            interpretacion     = interpretacion,\n            fecha_analisis     = analisis.fecha_analisis,\n        )\n\n    def historial_precios(\n        self,\n        meses: int = 6,\n        tipo_cafe: str = "pergamino_seco",\n    ) -> List[HistorialPrecioItem]:\n        """\n        RF-13: retorna el histórico mensual de precios para gráficas.\n        Agrupa por mes y fuente para mostrar comparativas FNC vs propio.\n        """\n        desde = datetime.utcnow() - timedelta(days=meses * 30)\n        registros = (\n            self.db.query(PrecioMercado)\n            .filter(\n                PrecioMercado.fecha_precio >= desde,\n                PrecioMercado.tipo_cafe == tipo_cafe,\n            )\n            .order_by(PrecioMercado.fecha_precio)\n            .all()\n        )\n\n        # Agrupar por mes\n        meses_dict: dict = {}\n        for r in registros:\n            clave = r.fecha_precio.strftime("%Y-%m")\n            if clave not in meses_dict:\n                meses_dict[clave] = {\n                    "todos": [], "fnc": [], "propio": []\n                }\n            meses_dict[clave]["todos"].append(float(r.precio_cop_kg))\n            if r.fuente == "fnc":\n                meses_dict[clave]["fnc"].append(float(r.precio_cop_kg))\n            if r.fuente == "propio_sistema":\n                meses_dict[clave]["propio"].append(float(r.precio_cop_kg))\n\n        resultado = []\n        for mes_key in sorted(meses_dict.keys()):\n            d        = meses_dict[mes_key]\n            todos    = d["todos"]\n            fnc_list = d["fnc"]\n            prp_list = d["propio"]\n            resultado.append(HistorialPrecioItem(\n                mes           = mes_key,\n                precio_prom   = round(sum(todos) / len(todos), 2),\n                precio_fnc    = round(sum(fnc_list) / len(fnc_list), 2) if fnc_list else None,\n                precio_propio = round(sum(prp_list) / len(prp_list), 2) if prp_list else None,\n                num_registros = len(todos),\n            ))\n        return resultado\n\n    # ----------------------------------------------------------\n    # RF-14 — ANÁLISIS DE DEMANDA\n    # ----------------------------------------------------------\n\n    def analizar_demanda(\n        self,\n        usuario_id:     int,\n        meses:          int = None,\n        observaciones:  Optional[DemandaObservacionCreate] = None,\n    ) -> AnalisisDemandaResponse:\n        """\n        RF-14: ejecuta el análisis de demanda del período.\n\n        Fuente de datos: tbl_trazabilidad_lote (M05)\n          - Lotes vendidos en el período\n          - Kg totales vendidos\n          - Tiempo promedio aprobación → venta\n          - Categoría más demandada\n          - Comprador más frecuente\n          - Destino principal\n\n        Si M05 no está disponible, opera con datos de precios propios\n        registrados en tbl_precio_mercado como fallback.\n        """\n        meses_analisis = meses or settings.MESES_HISTORICO_DEMANDA\n        ahora  = datetime.utcnow()\n        inicio = ahora - timedelta(days=meses_analisis * 30)\n        inicio_anterior = inicio - timedelta(days=meses_analisis * 30)\n\n        # ── Consultar M05 ───────────────────────────────────────\n        metricas = self._consultar_metricas_m05(inicio, ahora)\n        metricas_ant = self._consultar_metricas_m05(inicio_anterior, inicio)\n\n        total_lotes   = metricas.get("total_lotes", 0)\n        kg_totales    = metricas.get("kg_totales", 0.0)\n        kg_prom_lote  = metricas.get("kg_prom", None)\n        dias_prom     = metricas.get("dias_prom_venta", None)\n        cat_top       = metricas.get("categoria_top", None)\n        comprador_top = metricas.get("comprador_top", None)\n        destino_top   = metricas.get("destino_top", None)\n\n        total_lotes_ant = metricas_ant.get("total_lotes", 0)\n        variacion = calcular_variacion_porcentual(total_lotes, total_lotes_ant)\n\n        # ── Clasificar y generar recomendaciones ────────────────\n        nivel = clasificar_nivel_demanda(total_lotes, variacion, dias_prom)\n        recomendacion, interpretacion = generar_recomendacion_demanda(\n            nivel, total_lotes, kg_totales, dias_prom, cat_top, variacion\n        )\n\n        # ── Persistir ──────────────────────────────────────────\n        analisis = AnalisisDemanda(\n            periodo_inicio          = inicio,\n            periodo_fin             = ahora,\n            total_lotes_vendidos    = total_lotes,\n            kg_totales_vendidos     = kg_totales,\n            kg_promedio_por_lote    = kg_prom_lote,\n            dias_promedio_venta     = dias_prom,\n            categoria_mas_demandada = cat_top,\n            comprador_frecuente     = comprador_top,\n            destino_principal       = destino_top,\n            nivel_demanda           = nivel,\n            variacion_demanda_pct   = variacion,\n            observaciones_mercado   = observaciones.observaciones_mercado if observaciones else None,\n            oportunidades           = observaciones.oportunidades if observaciones else None,\n            riesgos                 = observaciones.riesgos if observaciones else None,\n            recomendacion           = recomendacion,\n            id_usuario              = usuario_id,\n        )\n        self.db.add(analisis)\n        self.db.commit()\n        self.db.refresh(analisis)\n\n        logger.info(\n            f"Análisis de demanda generado: nivel={nivel} "\n            f"lotes={total_lotes} kg={kg_totales:.0f}"\n        )\n\n        return AnalisisDemandaResponse(\n            id_demanda              = analisis.id_demanda,\n            periodo_inicio          = analisis.periodo_inicio,\n            periodo_fin             = analisis.periodo_fin,\n            total_lotes_vendidos    = analisis.total_lotes_vendidos,\n            kg_totales_vendidos     = float(analisis.kg_totales_vendidos),\n            kg_promedio_por_lote    = float(analisis.kg_promedio_por_lote) if analisis.kg_promedio_por_lote else None,\n            dias_promedio_venta     = analisis.dias_promedio_venta,\n            categoria_mas_demandada = analisis.categoria_mas_demandada,\n            comprador_frecuente     = analisis.comprador_frecuente,\n            destino_principal       = analisis.destino_principal,\n            nivel_demanda           = analisis.nivel_demanda,\n            nivel_demanda_label     = NIVEL_DEMANDA_LABELS.get(nivel, nivel),\n            variacion_demanda_pct   = analisis.variacion_demanda_pct,\n            variacion_label         = formatear_variacion_label(variacion),\n            observaciones_mercado   = analisis.observaciones_mercado,\n            oportunidades           = analisis.oportunidades,\n            riesgos                 = analisis.riesgos,\n            recomendacion           = analisis.recomendacion,\n            interpretacion          = interpretacion,\n            fecha_analisis          = analisis.fecha_analisis,\n        )\n\n    # ----------------------------------------------------------\n    # DASHBOARD CONSOLIDADO\n    # ----------------------------------------------------------\n\n    def dashboard_mercado(self, usuario_id: int) -> DashboardMercadoResponse:\n        """\n        Panel consolidado para el Comercializador.\n        Combina precio actual, stock disponible, demanda del mes\n        y proyección para apoyar decisiones comerciales (RF-13 + RF-14).\n        """\n        ahora  = datetime.utcnow()\n        inicio = ahora - timedelta(days=30)\n\n        # Sincronizar ventas propias antes del dashboard\n        self.sincronizar_ventas_propias(usuario_id)\n\n        # Último precio propio registrado\n        ultimo_precio = (\n            self.db.query(PrecioMercado)\n            .filter(PrecioMercado.fuente == "propio_sistema")\n            .order_by(PrecioMercado.fecha_precio.desc())\n            .first()\n        )\n        precio_actual = float(ultimo_precio.precio_cop_kg) if ultimo_precio else None\n\n        # Último precio FNC registrado\n        ultimo_fnc = (\n            self.db.query(PrecioMercado)\n            .filter(PrecioMercado.fuente == "fnc")\n            .order_by(PrecioMercado.fecha_precio.desc())\n            .first()\n        )\n        precio_fnc = float(ultimo_fnc.precio_cop_kg) if ultimo_fnc else settings.PRECIO_BASE_FNC_COP\n\n        diferencial = None\n        if precio_actual and precio_fnc:\n            diferencial = round((precio_actual - precio_fnc) / precio_fnc * 100, 1)\n\n        # Último análisis de precio\n        ultimo_analisis = (\n            self.db.query(AnalisisPrecio)\n            .order_by(AnalisisPrecio.fecha_analisis.desc())\n            .first()\n        )\n        tendencia_actual     = ultimo_analisis.tendencia if ultimo_analisis else None\n        alerta_precio        = ultimo_analisis.alerta_activa if ultimo_analisis else False\n        msg_alerta_precio    = ultimo_analisis.mensaje_alerta if ultimo_analisis else None\n        precio_proyectado    = (\n            float(ultimo_analisis.precio_proyectado)\n            if ultimo_analisis and ultimo_analisis.precio_proyectado else None\n        )\n\n        # Lotes y kg disponibles (M05)\n        lotes_disp, kg_disp = self._lotes_disponibles()\n\n        # Ventas del mes en curso (M05)\n        metricas_mes = self._consultar_metricas_m05(inicio, ahora)\n        lotes_mes    = metricas_mes.get("total_lotes", 0)\n        kg_mes       = metricas_mes.get("kg_totales", 0.0)\n\n        # Nivel de demanda del último análisis\n        ultimo_demanda = (\n            self.db.query(AnalisisDemanda)\n            .order_by(AnalisisDemanda.fecha_analisis.desc())\n            .first()\n        )\n        nivel_demanda = (\n            NIVEL_DEMANDA_LABELS.get(ultimo_demanda.nivel_demanda)\n            if ultimo_demanda else None\n        )\n\n        # Recomendación combinada\n        if alerta_precio and tendencia_actual == "baja":\n            reco = (\n                "Precios en baja y alerta activa. Evalúe si tiene urgencia de venta. "\n                "Mantenga comunicación con sus compradores habituales."\n            )\n        elif lotes_disp > 0 and tendencia_actual == "alza":\n            reco = (\n                f"Tiene {lotes_disp} lote(s) aprobado(s) disponibles y los precios están al alza. "\n                "Buen momento para iniciar negociaciones de venta."\n            )\n        elif lotes_disp == 0:\n            reco = "Sin lotes aprobados disponibles. Enfóquese en preparar nuevos lotes."\n        else:\n            reco = (\n                "Condiciones estables. Revise los análisis de precio y demanda "\n                "para tomar decisiones informadas."\n            )\n\n        # Alertas activas\n        alertas = []\n        if alerta_precio and msg_alerta_precio:\n            alertas.append(msg_alerta_precio)\n        if lotes_disp == 0:\n            alertas.append("Sin stock aprobado disponible para venta.")\n        if ultimo_demanda and ultimo_demanda.nivel_demanda == "baja":\n            alertas.append("La demanda del período es baja. Diversifique canales de venta.")\n\n        return DashboardMercadoResponse(\n            precio_actual_cop      = precio_actual,\n            precio_fnc_referencia  = precio_fnc,\n            diferencial_fnc_pct    = diferencial,\n            tendencia_precio       = tendencia_actual,\n            alerta_precio          = alerta_precio,\n            mensaje_alerta_precio  = msg_alerta_precio,\n            lotes_disponibles      = lotes_disp,\n            kg_disponibles         = kg_disp,\n            total_vendido_mes      = lotes_mes,\n            kg_vendidos_mes        = kg_mes,\n            nivel_demanda_actual   = nivel_demanda,\n            precio_proyectado_mes  = precio_proyectado,\n            recomendacion_comercial= reco,\n            alertas                = alertas,\n            fecha_actualizacion    = ahora,\n        )\n\n    # ----------------------------------------------------------\n    # HELPERS PRIVADOS\n    # ----------------------------------------------------------\n\n    def _consultar_metricas_m05(\n        self, inicio: datetime, fin: datetime\n    ) -> dict:\n        """\n        Consulta métricas de ventas de M05 para el período dado.\n        Retorna dict vacío si tbl_trazabilidad_lote no está disponible.\n        """\n        try:\n            r = self.db.execute(\n                text("""\n                    SELECT\n                        COUNT(*)                          AS total_lotes,\n                        COALESCE(SUM(kg_pergamino_seco), 0) AS kg_totales,\n                        AVG(kg_pergamino_seco)            AS kg_prom,\n                        -- BUG-010 FIX: columnas verificadas contra modelo TrazabilidadLote\n                        AVG(DATEDIFF(fecha_venta,\n                            COALESCE(fecha_fin_secado, fecha_registro)))\n                                                          AS dias_prom_venta\n                    FROM tbl_trazabilidad_lote\n                    WHERE estado = \'vendido\'\n                      AND fecha_venta BETWEEN :ini AND :fin\n                """),\n                {"ini": inicio, "fin": fin},\n            ).fetchone()\n\n            top_cat = self.db.execute(\n                text("""\n                    SELECT clasificacion_calidad, COUNT(*) AS cnt\n                    FROM   tbl_trazabilidad_lote\n                    WHERE  estado = \'vendido\'\n                      AND  fecha_venta BETWEEN :ini AND :fin\n                    GROUP BY clasificacion_calidad\n                    ORDER BY cnt DESC LIMIT 1\n                """),\n                {"ini": inicio, "fin": fin},\n            ).fetchone()\n\n            top_comp = self.db.execute(\n                text("""\n                    SELECT comprador, COUNT(*) AS cnt\n                    FROM   tbl_trazabilidad_lote\n                    WHERE  estado = \'vendido\'\n                      AND  comprador IS NOT NULL\n                      AND  fecha_venta BETWEEN :ini AND :fin\n                    GROUP BY comprador\n                    ORDER BY cnt DESC LIMIT 1\n                """),\n                {"ini": inicio, "fin": fin},\n            ).fetchone()\n\n            top_dest = self.db.execute(\n                text("""\n                    SELECT destino_exportacion, COUNT(*) AS cnt\n                    FROM   tbl_trazabilidad_lote\n                    WHERE  estado = \'vendido\'\n                      AND  destino_exportacion IS NOT NULL\n                      AND  fecha_venta BETWEEN :ini AND :fin\n                    GROUP BY destino_exportacion\n                    ORDER BY cnt DESC LIMIT 1\n                """),\n                {"ini": inicio, "fin": fin},\n            ).fetchone()\n\n            return {\n                "total_lotes":      int(r.total_lotes) if r else 0,\n                "kg_totales":       float(r.kg_totales) if r and r.kg_totales else 0.0,\n                "kg_prom":          float(r.kg_prom) if r and r.kg_prom else None,\n                "dias_prom_venta":  float(r.dias_prom_venta) if r and r.dias_prom_venta else None,\n                "categoria_top":    top_cat.clasificacion_calidad if top_cat else None,\n                "comprador_top":    top_comp.comprador if top_comp else None,\n                "destino_top":      top_dest.destino_exportacion if top_dest else None,\n            }\n        except Exception as e:\n            logger.warning(f"M05 no disponible para métricas de demanda: {e}")\n            return {}\n\n    def _lotes_disponibles(self):\n        """Retorna (total_lotes, kg_totales) de lotes en estado \'aprobado\'."""\n        try:\n            r = self.db.execute(\n                text("""\n                    SELECT COUNT(*) AS lotes,\n                           COALESCE(SUM(kg_pergamino_seco), 0) AS kg\n                    FROM   tbl_trazabilidad_lote\n                    WHERE  estado = \'aprobado\'\n                """)\n            ).fetchone()\n            return int(r.lotes), float(r.kg)\n        except Exception:\n            return 0, 0.0\n\n    def _serie_mensual_precios(\n        self, tipo_cafe: str, fuente: str, num_meses: int\n    ) -> List[float]:\n        """Retorna lista de promedios mensuales para proyección WMA-3."""\n        desde = datetime.utcnow() - timedelta(days=num_meses * 30)\n        q = self.db.query(PrecioMercado).filter(\n            PrecioMercado.fecha_precio >= desde,\n            PrecioMercado.tipo_cafe == tipo_cafe,\n        )\n        if fuente and fuente != "todas":\n            q = q.filter(PrecioMercado.fuente == fuente)\n\n        registros = q.order_by(PrecioMercado.fecha_precio).all()\n        if not registros:\n            return []\n\n        meses_dict: dict = {}\n        for r in registros:\n            clave = r.fecha_precio.strftime("%Y-%m")\n            meses_dict.setdefault(clave, []).append(float(r.precio_cop_kg))\n\n        return [\n            round(sum(v) / len(v), 2)\n            for v in [meses_dict[k] for k in sorted(meses_dict.keys())]\n        ]\n\n    def _precio_a_response(self, p: PrecioMercado) -> PrecioResponse:\n        return PrecioResponse(\n            id_precio         = p.id_precio,\n            fuente            = p.fuente,\n            tipo_cafe         = p.tipo_cafe,\n            precio_cop_kg     = float(p.precio_cop_kg),\n            precio_usd_lb     = float(p.precio_usd_lb) if p.precio_usd_lb else None,\n            variedad          = p.variedad,\n            categoria_calidad = p.categoria_calidad,\n            region            = p.region,\n            notas             = p.notas,\n            id_lote_origen    = p.id_lote_origen,\n            fecha_precio      = p.fecha_precio,\n            fecha_registro    = p.fecha_registro,\n        )\n'

